// ─── BTS Prothésiste Dentaire ───
const T={accent:"#FF5DA0",green:"#4AEAAC",blue:"#5EB5FF",orange:"#FFB259",yellow:"#F0E547",text2:"#A199B2"};

// ─── BANQUES DE QUESTIONS ───

export const QB_PD_SCIENCES = [
  {id:"pd_s1",prompt:"La dent se compose de :",choices:["L'émail uniquement","L'émail, la dentine, le cément et la pulpe","L'émail et l'os alvéolaire","La dentine et le cément uniquement"],answer:1,diff:1,explication:"Structure dentaire : émail (partie coronaire visible, tissu le plus dur du corps humain, 96% minéral), dentine (tissu principal, moins minéralisé, avec tubules), pulpe (tissu conjonctif vivant, vaisseaux et nerfs), cément (racine).",tags:["Anatomie","Dent","Structure dentaire"]},
  {id:"pd_s2",prompt:"L'émail dentaire est produit par :",choices:["Les odontoblastes","Les améloblastes (lors de l'amélogénèse, irréversible après éruption)","Les cémentoblastes","Les ostéoblastes"],answer:1,diff:2,explication:"Améloblastes → émail (amélogénèse). Odontoblastes → dentine (dentinogénèse, persistant dans la pulpe). Cémentoblastes → cément. Ostéoblastes → os alvéolaire.",tags:["Anatomie","Émail","Amélogénèse","Histologie"]},
  {id:"pd_s3",prompt:"Le parodonte comprend :",choices:["Uniquement la gencive","Gencive, ligament alvéolo-dentaire (desmodonte), os alvéolaire et cément","La pulpe et la dentine","L'émail et l'os"],answer:1,diff:1,explication:"Parodonte = tissu de soutien de la dent : gencive (protection), ligament parodontal/desmodonte (amortissement), os alvéolaire (support osseux), cément (ancrage des fibres de Sharpey).",tags:["Anatomie","Parodonte","Tissu de soutien"]},
  {id:"pd_s4",prompt:"La formule dentaire d'un adulte (32 dents) est :",choices:["2.1.2.2 / 2.1.2.2","2.1.2.3 / 2.1.2.3 (incisives/canine/prémolaires/molaires)","1.1.2.3 / 1.1.2.3","3.1.2.2 / 3.1.2.2"],answer:1,diff:1,explication:"Formule dentaire adulte (demi-mâchoire) : 2 incisives + 1 canine + 2 prémolaires + 3 molaires = 8 dents × 4 = 32 dents. Notation internationale (FDI) : dents 11 à 18, 21 à 28, 31 à 38, 41 à 48.",tags:["Anatomie","Formule dentaire","Nomenclature FDI"]},
  {id:"pd_s5",prompt:"L'occlusion de classe I d'Angle se caractérise par :",choices:["Une cuspide mésio-buccale de la 1ère molaire supérieure en retrait","La cuspide mésio-buccale de la 1ère molaire supérieure en rapport avec le sillon central de la 1ère molaire inférieure","La molaire supérieure en avant de la molaire inférieure","L'absence de relation molaire définie"],answer:1,diff:2,explication:"Classes d'Angle : I = rapport molaire normal (eugnathie). II = molaire inf en arrière (division 1 : proalvéolie, division 2 : rétroalvéolie). III = molaire inf en avant (progénie). Base du diagnostic orthodontique.",tags:["Anatomie","Occlusion","Classes d'Angle","Orthodontie"]},
  {id:"pd_s6",prompt:"Le guide antérieur (glissement incisif) joue un rôle dans :",choices:["La mastication des aliments durs uniquement","La désocclusion postérieure lors des mouvements mandibulaires (propulsion, diduction)","La déglutition","La phonétique uniquement"],answer:1,diff:2,explication:"Guide antérieur : contact des incisives lors de la propulsion mandibulaire → séparation des dents postérieures. Protège les dents cuspidées. Reconstruction du guide antérieur = impératif en prothèse fixée.",tags:["Anatomie","Occlusion","Guide antérieur","Articulé dentaire"]},
  {id:"pd_s7",prompt:"L'ATM (Articulation Temporo-Mandibulaire) comprend :",choices:["Deux os en contact direct","Le condyle mandibulaire, la fosse temporale, le disque articulaire, les ligaments et les muscles ptérygoïdiens","Uniquement les muscles masséters","Le condyle et la dent"],answer:1,diff:2,explication:"ATM (bilatérale) : condyle mandibulaire + fosse glénoïde temporale + disque articulaire fibrocartilagineux (interposé entre les deux). Muscles : ptérygoïdien latéral (protraction), temporal, masséter, ptérygoïdien médial.",tags:["Anatomie","ATM","Mandibule","Articulé"]},
  {id:"pd_s8",prompt:"La résine composite à base de BisGMA est principalement utilisée pour :",choices:["Les armatures de prothèse amovible","Les composites de restauration directe et les résines de bridge (prothèse transitoire)","Les alliages de coulée","Les empreintes à base de silicone"],answer:1,diff:2,explication:"BisGMA (bisphénol A glycidyl méthacrylate) : matrice organique des résines composites. Polymérisé par lumière bleue (λ 460-500 nm) ou chimiquement. Applications : restaurations directes/indirectes, prothèse transitoire, composite de stratification.",tags:["Biomatériaux","Résine composite","BisGMA","Photopolymérisation"]},
  {id:"pd_s9",prompt:"La céramique feldspathique se distingue de la zircone par :",choices:["Sa résistance mécanique supérieure","Sa translucidité supérieure et son esthétique (mais résistance mécanique moindre)","Son utilisation en prothèse amovible","Son absence d'indication en prothèse fixée"],answer:1,diff:2,explication:"Céramique feldspathique (frittée, stratifiée) : excellente esthétique, translucidité proche de la dent naturelle. Fragilité (module de rupture ≈ 100-150 MPa). Zircone (YZ) : très résistante (1000+ MPa) mais moins translucide. Zircone translucide multicouche (PMMA → haute translucidité).",tags:["Biomatériaux","Céramique","Zircone","Esthétique"]},
  {id:"pd_s10",prompt:"L'alliage cobalt-chrome (Co-Cr) est principalement utilisé pour :",choices:["Les inlays en céramique","Les châssis de prothèses amovibles partielles (résistance, légèreté, biocompatibilité)","Les couronnes esthétiques en métal-céramique","Les implants dentaires"],answer:1,diff:1,explication:"Co-Cr : alliage de base, résistant (module élevé), léger, biocompatible, non précieux. Idéal pour châssis PAP (coulée ou CFAO). Métaux précieux (or, palladium) pour métal-céramique (adhésion optimale).",tags:["Biomatériaux","Alliages","Co-Cr","Châssis PAP"]},
  {id:"pd_s11",prompt:"Le silicone de condensation (C-silicone) se distingue du silicone d'addition (A-silicone) par :",choices:["Sa précision supérieure","Sa rétraction à la prise + évaporation de sous-produits (alcool) → moins précis, moins stable","Sa couleur","Sa viscosité uniquement"],answer:1,diff:2,explication:"C-silicone : condensation = polymérisation avec libération d'alcool → légère rétraction dimensionnelle. A-silicone (polyvinylsiloxane) : addition = pas de sous-produit → grande précision, stabilité dimensionnelle. Standard pour empreintes couronne/bridge.",tags:["Biomatériaux","Empreinte","Silicone","Précision"]},
  {id:"pd_s12",prompt:"L'hydrocolloïde irréversible (alginate) est utilisé pour :",choices:["Les empreintes de précision en prothèse fixée","Les empreintes de diagnostic, maquettes, et certaines PAP (économique, rapide)","Les empreintes implantaires","Les enregistrements de l'occlusion"],answer:1,diff:1,explication:"Alginate : hydrocolloïde irréversible, économique, rapide, mais hydrophile et instable (distorsion → couler immédiatement). Usage : modèles d'étude, prothèse amovible de masse, orthopédie dento-faciale.",tags:["Biomatériaux","Alginate","Empreinte","Prothèse amovible"]},
];

export const QB_PD_TECHNIQUE = [
  {id:"pd_t1",prompt:"La CFAO (Conception et Fabrication Assistées par Ordinateur) en prothèse dentaire comprend :",choices:["Uniquement l'impression 3D","Acquisition numérique (scanner ou empreinte optique) → conception (logiciel CAD) → fabrication (usinage MOCN ou impression 3D)","Uniquement l'usinage","Uniquement le fraisage de la zircone"],answer:1,diff:1,explication:"CFAO (CAD/CAM) : numérisation (scannage modèle ou empreinte optique intra-orale) → fichier STL → conception 3D (Cerec, 3Shape, exocad...) → fabrication (usinage MOCN, impression SLA/DLP/FDM).",tags:["CFAO","CAD/CAM","Numérique","Prothèse"]},
  {id:"pd_t2",prompt:"Le fraisage (MOCN — Machine-Outil à Commande Numérique) en prothèse dentaire usine :",choices:["Uniquement des métaux","Des matériaux blocs (zircone, PMMA, e.max, titane) par enlèvement de matière","Des résines par photopolymérisation","Des alliages par coulée centrifuge"],answer:1,diff:1,explication:"Usinage MOCN : fraise des blocs solides par enlèvement de matière (outil rotatif). Matériaux : zircone préfrittée (sintering ultérieur), PMMA, disilicate de lithium (e.max), titane. Précision ± 20-50 µm.",tags:["CFAO","Usinage","Zircone","MOCN"]},
  {id:"pd_t3",prompt:"L'impression 3D par stéréolithographie (SLA) produit des pièces par :",choices:["Dépôt de filament fondu","Photopolymérisation d'une résine liquide par un laser UV couche par couche","Fraisage d'un bloc","Coulée sous pression"],answer:1,diff:2,explication:"SLA : laser UV polymérise la résine photosensible couche par couche (25-100 µm). Haute résolution. Applications dentaires : maquettes, guides chirurgicaux, prothèse transitoire, gouttières. Résines biocompatibles spécifiques.",tags:["CFAO","Impression 3D","SLA","Résine"]},
  {id:"pd_t4",prompt:"Le frittage de la zircone après usinage entraîne :",choices:["Une expansion du bloc","Un retrait dimensionnel d'environ 20-25% (à compenser lors de la conception)","Aucune modification de volume","Un changement de couleur uniquement"],answer:1,diff:2,explication:"Zircone pré-frittée (white phase) : poreuse, usinable facilement. Après frittage (1450-1550°C) : cristallisation (phase tétragonale → cubique pour haute translucidité), retrait ~20-25%. Logiciel CFAO compense automatiquement.",tags:["CFAO","Zircone","Frittage","Retrait"]},
  {id:"pd_t5",prompt:"La prothèse amovible partielle (PAP) à châssis métallique comprend :",choices:["Uniquement des dents en résine","Châssis Co-Cr (connecteur principal, selles, crochets, taquets occlusaux) + dents prothétiques en résine ou céramique","Uniquement des implants","Un bridge fixé sur implants"],answer:1,diff:1,explication:"PAP châssis : connecteur principal (barre palatine, barre mandibulaire) + connecteurs secondaires + selles (résine + dents) + rétentions (crochets coulés ou fil, taquets occlusaux). Co-Cr ou titane CFAO.",tags:["Prothèse amovible","PAP","Châssis","Co-Cr"]},
  {id:"pd_t6",prompt:"La prothèse complète (PAC) est indiquée chez les patients :",choices:["Ayant encore des dents piliers","Complètement édentés (maxillaire ou mandibulaire ou les deux)","Avec implants uniquement","Avec prothèse fixée déjà posée"],answer:1,diff:1,explication:"PAC : prothèse muqueuse portée par la crête alvéolaire édentée. Rétention par aspiration (joint périphérique), adhésion, gravité. Anatomie : bord limite, empreinte de primaire + secondaire (joint bordant).",tags:["Prothèse amovible","PAC","Édenté total","Rétention"]},
  {id:"pd_t7",prompt:"L'empreinte de travail pour une couronne en prothèse fixée est réalisée avec :",choices:["De l'alginate uniquement","Un matériau d'empreinte de précision (A-silicone, polyéther) + technique double-mélange ou monophasique","De la cire uniquement","Du plâtre de Paris"],answer:1,diff:1,explication:"Empreinte de précision (PF) : A-silicone (polyvinylsiloxane) ou polyéther. Technique double-mélange (body + putty) ou monophasique (medium). Obtenir une empreinte nette de la préparation et du joint cervical.",tags:["Prothèse fixée","Empreinte","A-silicone","Précision"]},
  {id:"pd_t8",prompt:"Une couronne céramo-métallique (CCM) présente :",choices:["Aucune armature","Une armature métallique (cobalt-chrome, or) recouverte de céramique cosmétique frittée","Un bloc de zircone intégral","Uniquement de la résine"],answer:1,diff:1,explication:"CCM : armature métal (opaque bruit métal) recouvert de céramique stratifiée (dentine + émail + incisif). Bonne résistance, durabilité (20-30 ans). Esthétique limitée au collet (liseré métallique). Remplacée progressivement par tout-céramique.",tags:["Prothèse fixée","Couronne","Céramique","Métal-céramique"]},
  {id:"pd_t9",prompt:"Un bridge 3 éléments nécessite :",choices:["3 implants obligatoires","2 dents piliers préparées + 1 intermédiaire de bridge (pontique)","1 seule dent pilier","4 dents piliers minimum"],answer:1,diff:1,explication:"Bridge conventionnel 3 éléments : 2 éléments rétenteurs (couronnes sur dents piliers préparées) + 1 pontique (remplace la dent absente). Connexion rigide. Irréversible (préparation des piliers).",tags:["Prothèse fixée","Bridge","Piliers","Pontique"]},
  {id:"pd_t10",prompt:"Le protocole d'assemblage d'une couronne tout-céramique comprend :",choices:["Collage direct sans préparation","Mordançage acide fluorhydrique (HF) + silanisation de la céramique + ciment de collage dual (composite)","Ciment verre ionomère systématiquement","Oxyde de zinc eugénol uniquement"],answer:1,diff:3,explication:"Collage céramique : 1) Mordançage HF 9.5% (30-60s pour feldspathique, 20s pour e.max) → rugosification surface. 2) Silanisation (liaison chimique). 3) Ciment composite dual (Variolink, RelyX). Essai à sec avant collage définitif.",tags:["Prothèse fixée","Collage","Céramique","Mordançage"]},
  {id:"pd_t11",prompt:"L'implant dentaire (implant ostéo-intégré selon Brånemark) est principalement en :",choices:["Or","Titane (grade 4 ou alliage Ti-6Al-4V) ou zircone (implants céramiques)","Acier inoxydable","Cobalt-chrome"],answer:1,diff:1,explication:"Implants Brånemark (1965) : titane grade 4 (commercialement pur) ou alliage Ti-6Al-4V. Ostéo-intégration (contact direct os-titane, sans tissu fibreux interposé). Implants zircone : alternative pour allergie/esthétique.",tags:["Implantologie","Titane","Ostéointégration","Brånemark"]},
  {id:"pd_t12",prompt:"La prothèse provisoire (transitoire) en prothèse fixée a pour rôle :",choices:["Être définitive","Protéger la dent préparée, tester le guide antérieur, maintenir l'espace et conditionner les tissus parodontaux pendant la fabrication de la prothèse définitive","Remplacer la prothèse fixée en cas d'échec","Mesurer l'occlusion uniquement"],answer:1,diff:2,explication:"Provisoire (PMMA photopolymérisé ou composite) : protection dentino-pulpaire, maintien de l'espace et de l'occlusion, guide antérieur, test esthétique et fonctionnel, gestion des tissus parodontaux. Collée avec ciment temporaire.",tags:["Prothèse fixée","Provisoire","PMMA","Transition"]},
];

export const QB_PD_PARO_HYGIENE = [
  {id:"pd_ph1",prompt:"La gingivite se distingue de la parodontite par :",choices:["La douleur uniquement","La réversibilité : la gingivite est réversible (inflammation superficielle), la parodontite implique une perte d'attache irréversible","La présence de plaque dentaire","La couleur de la gencive uniquement"],answer:1,diff:1,explication:"Gingivite : inflammation gencivale, réversible avec un traitement parodontal et une bonne hygiène. Parodontite : destruction irréversible du ligament parodontal, de l'os alvéolaire et du cément (perte d'attache).",tags:["Parodontologie","Gingivite","Parodontite","Hygiène"]},
  {id:"pd_ph2",prompt:"L'indice de plaque de Silness et Löe évalue :",choices:["La profondeur de poche parodontale","La quantité de plaque dentaire à l'interface dento-gingivale (0 = pas de plaque, 3 = plaque abondante)","L'inflammation gingivale uniquement","La mobilité dentaire"],answer:1,diff:2,explication:"Indice de plaque (Silness-Löe) : 0 (absent) à 3 (plaque visible à l'œil nu). Évaluation sur 4 faces de 6 dents repère. Base du bilan parodontal initial et du suivi post-thérapeutique.",tags:["Parodontologie","Indice de plaque","Silness-Löe","Diagnostic"]},
  {id:"pd_ph3",prompt:"Un sondage parodontal de 6 mm indique :",choices:["Une poche physiologique (normale)","Une poche parodontale pathologique (poche > 3 mm chez l'adulte sain)","Une récession gingivale","Une gingivite uniquement"],answer:1,diff:1,explication:"Sondage parodontal (sonde graduée de Williams) : 0-3 mm = sulcus normal. 4-5 mm = poche initiale. 6 mm = poche avancée. > 6 mm = poche profonde. Mesure sur 6 sites par dent.",tags:["Parodontologie","Sondage","Poche parodontale","Diagnostic"]},
  {id:"pd_ph4",prompt:"La désinfection d'une empreinte en silicone après prélèvement doit être réalisée :",choices:["Jamais, l'empreinte est propre","Dès réception au laboratoire : rinçage eau + désinfection par trempage ou pulvérisation (glutaraldéhyde ou hypochlorite dilué)","Uniquement si le patient a une hépatite","Avant l'empreinte, pas après"],answer:1,diff:2,explication:"Toute empreinte (et prothèse retournée) est considérée contaminée. Protocole : rinçage eau (élimine salive/sang) + désinfection (glutaraldéhyde 2%, hypochlorite 0.5%, ou produit validé) + séchage avant mise en articulateur.",tags:["Hygiène laboratoire","Désinfection","Empreinte","Risque infectieux"]},
  {id:"pd_ph5",prompt:"Le masque FFP2 est recommandé en laboratoire de prothèse lors de :",choices:["Toutes les activités","L'usinage de la zircone, le plâtrage, le ponçage (protection contre les poussières fines < 5 µm)","Uniquement lors de la coulée des alliages","La photopolymérisation des résines"],answer:1,diff:1,explication:"FFP2 (filtration > 94%) : protection contre les poussières inhalables fines (zircone, PMMA, plâtre, alliages). La silice (quartz) et la zircone sont potentiellement fibrogènes. FFP3 (> 99%) pour les poussières carcinogènes.",tags:["Hygiène laboratoire","FFP2","EPI","Zircone","Poussières"]},
  {id:"pd_ph6",prompt:"La réglementation européenne MDR 2017/745 classe les prothèses dentaires sur mesure en :",choices:["Classe I (risque faible)","Classe IIa (risque modéré — dispositifs médicaux sur mesure impliquant un chirurgien-dentiste)","Classe III (risque élevé)","Classe IV"],answer:1,diff:2,explication:"MDR 2017/745 : prothèses dentaires (couronne, bridge, PAP, PAC) = dispositifs médicaux sur mesure classe IIa. Exigences : déclaration de conformité, dossier technique, traçabilité, système QMS. En vigueur depuis mai 2021.",tags:["Réglementation","MDR","Dispositif médical","DM classe IIa"]},
  {id:"pd_ph7",prompt:"La traçabilité d'une prothèse dentaire sur mesure comprend obligatoirement :",choices:["Uniquement le nom du patient","Fiche suiveuse : patient (nom, date naissance), prescripteur, date, matériaux utilisés (références, lots), technicien, contrôles qualité","Uniquement les matériaux","Le numéro de sécu du patient uniquement"],answer:1,diff:2,explication:"Traçabilité MDR : dossier technique par pièce. Identification univoque, matériaux (nom commercial + lot), contrôles, opérateur. Conservation 10 ans minimum. Déclaration ANSM en cas d'incident.",tags:["Réglementation","Traçabilité","MDR","Prothèse"]},
  {id:"pd_ph8",prompt:"Le bon de travail (ou prescription du chirurgien-dentiste) doit comporter :",choices:["Uniquement le nom du patient","Identification patient, type de prothèse, dents concernées, teinte, matériaux souhaités, date de livraison, signature du chirurgien-dentiste","Uniquement la teinte","Le numéro de sécu et la teinte"],answer:1,diff:1,explication:"Prescription / bon de travail (BTL) : obligatoire pour chaque prothèse. Doit inclure : identité patient, identification praticien, description prothèse, teinte, matériaux, date livraison, signature. Document médico-légal.",tags:["Réglementation","Bon de travail","Communication CD/prothésiste","Prescription"]},
  {id:"pd_ph9",prompt:"L'autoclave de laboratoire dentaire (désinfection des instruments) fonctionne à :",choices:["100°C","121°C, 1 bar, 15-20 min (ou 134°C pour les instruments à risque prions)","60°C en 30 min","Température ambiante avec UV"],answer:1,diff:1,explication:"Stérilisation par chaleur humide (autoclave) : 121°C / 1 bar / 15-20 min = cycle standard. 134°C / 2 bars / 18 min = cycle prions (instruments à risque neurochirurgical). Indicateurs biologiques pour validation.",tags:["Hygiène laboratoire","Autoclave","Stérilisation","Prions"]},
  {id:"pd_ph10",prompt:"L'oxyde de zinc eugénol (ZOE) est contre-indiqué pour la prothèse provisoire sous bridge collé car :",choices:["Il est trop cher","L'eugénol inhibe la polymérisation des résines composites (ciments de collage résine)","Il durcit trop vite","Il est allergisant dans 100% des cas"],answer:1,diff:2,explication:"Eugénol = phénol → inhibe la polymérisation radicalaire des ciments composites. Contamination de la surface dentinaire par ZOE → échec de collage. Utiliser ciment provisoire sans eugénol (ZOE-free) sous future restauration collée.",tags:["Prothèse fixée","Eugénol","Collage","Contraindication"]},
  {id:"pd_ph11",prompt:"La teinte des dents prothétiques est déterminée avec :",choices:["Uniquement la mesure spectrophotométrique","Le teintier Vita Classical (A1-D4) ou 3D Master (tonus, valeur, chroma) + spectrophotomètre pour objectiver","Uniquement la comparaison visuelle","Le guide des teintes fourni par le praticien"],answer:1,diff:1,explication:"Teintier VITA : 3D Master (évalue d'abord la valeur/luminosité, puis le groupe de teinte, enfin la chroma). Classical (A1-D4). Spectrophotomètre : mesure objective L*a*b*. Conditions : lumière naturelle + humidification dents.",tags:["Esthétique","Teinte","VITA","Prothèse"]},
  {id:"pd_ph12",prompt:"La gestion des déchets contaminés (empreintes, gants usagés, polissages) en laboratoire de prothèse :",choices:["Poubelle ordinaire","Filière DASRI (Déchets d'Activités de Soins à Risques Infectieux) pour tout déchet ayant été en contact avec le patient","Recyclage","Incinération par le prothésiste lui-même"],answer:1,diff:1,explication:"Empreintes, prothèses retournées, gants, masques : DASRI potentiels. Filière spécialisée : conteneurs DASRI (rigides étanches), collecteur agréé. Réglementation : décret DASRI 1997, mise à jour 2010.",tags:["Hygiène laboratoire","DASRI","Déchets","Réglementation"]},
  {id:"pd_ph13",prompt:"L'articulateur semi-adaptable simule les mouvements de la mandibule en :",choices:["Uniquement l'ouverture/fermeture","Propulsion, diduction gauche et droite, et l'angle de Bennett (mouvement latéral)","Uniquement la mastication","Déglutition et phonation"],answer:1,diff:2,explication:"Articulateur semi-adaptable (type Quick Master, Artex) : réglage de l'angle de la pente condylienne (propulsion) et de l'angle de Bennett (diduction). Arc facial → report du positionnement du maxillaire par rapport à l'ATM.",tags:["Prothèse amovible","Articulateur","Occlusion","Bennett"]},
  {id:"pd_ph14",prompt:"Le frittage final de la zircone en laboratoire de prothèse est réalisé à :",choices:["600°C","1450-1550°C pendant 6-8h dans un four de frittage spécifique","200°C","3000°C"],answer:1,diff:2,explication:"Frittage zircone : 1450-1550°C (selon type : 3Y-TZP pour bicouches, 5Y pour haute translucidité). Durée 6-8h (montée + plateau + descente). Retrait précis de 20-25% (compensé par le logiciel CFAO). Four de frittage dédié.",tags:["CFAO","Zircone","Frittage","Laboratoire"]},
  {id:"pd_ph15",prompt:"La surveillance biologique du prothésiste (médecine du travail) inclut notamment :",choices:["Aucune surveillance spécifique","Surveillance des expositions aux métaux (Co, Cr, Ni dosages urinaires), aux monomères (DMDS sanguins), et aux poussières (spirométrie)","Uniquement la radiographie pulmonaire annuelle","Uniquement les tests allergiques"],answer:1,diff:2,explication:"Risques spécifiques prothèse dentaire : Co-Cr (sensibilisation, dermatite), MMA/HEMA (allergies cutanées), Si/zircone (pneumoconiose). Surveillance AT/MP : déclarations, médecine du travail, fiche de poste.",tags:["Hygiène laboratoire","Médecine du travail","Risques chimiques","Surveillance"]},
];

export const QB_PD_KENNEDY = [
  {id:"pd_k1",prompt:"La classification de Kennedy classe les édentements partiels selon :",choices:["Le nombre de dents absentes","La position du/des édentement(s) par rapport aux dents restantes (encastré ou en extension)","La profondeur de la poche parodontale","La couleur des dents résiduelles"],answer:1,diff:1,explication:"La classification de Kennedy (1925) classe les édentements partiels en 4 classes selon la relation topographique entre l'édentement et les dents résiduelles : encastré (les deux extrémités sont dentées) ou terminal/en extension (au moins une extrémité est libre). Base du diagnostic de PAP.",tags:["Prothèse amovible","Kennedy","Édentement","Classification"]},
  {id:"pd_k2",prompt:"La classe I de Kennedy correspond à :",choices:["Un édentement antérieur qui traverse la ligne médiane","Un édentement unilatéral encastré","Une édentation bilatérale postérieure terminale (libre des deux côtés)","Un édentement unilatéral postérieur terminal"],answer:2,diff:1,explication:"Classe I : édentation bilatérale postérieure terminale. Les deux zones d'édentement sont postérieures et libres distalement (pas de dents distales). Situation la plus délicate bioméchaniquement → crochets semi-rigides nécessaires (appui mixte muco-dento-ostéo).",tags:["Prothèse amovible","Kennedy","Classe I","Édentement bilatéral"]},
  {id:"pd_k3",prompt:"La classe II de Kennedy se caractérise par :",choices:["Un édentement bilatéral postérieur terminal","Un édentement unilatéral postérieur terminal (une seule zone libre distalement)","Un édentement encastré (intercalaire) bilatéral","Un édentement antérieur"],answer:1,diff:1,explication:"Classe II : édentation unilatérale postérieure terminale (un seul côté libre distalement). Elle se distingue de la classe I par son caractère unilatéral. Crochets semi-rigides du côté édenté (terminal), crochets rigides du côté denté.",tags:["Prothèse amovible","Kennedy","Classe II","Édentement unilatéral"]},
  {id:"pd_k4",prompt:"La classe III de Kennedy correspond à :",choices:["Un édentement postérieur terminal bilatéral","Un édentement antérieur","Un édentement unilatéral encastré (dents présentes des deux côtés de l'édentement)","Un édentement terminal unilatéral sans canine"],answer:2,diff:1,explication:"Classe III : édentation unilatérale postérieure encastrée (intercalaire). Des dents sont présentes de part et d'autre de la zone édentée. C'est la classe la plus fréquente. Support essentiellement dento-parodontal → crochets rigides.",tags:["Prothèse amovible","Kennedy","Classe III","Édentement encastré"]},
  {id:"pd_k5",prompt:"La classe IV de Kennedy est définie comme :",choices:["Un édentement postérieur bilatéral","Un édentement antérieur unique traversant ou englobant la ligne médiane","Deux édentements encastrés postérieurs","Un édentement associé à une perte de canine"],answer:1,diff:2,explication:"Classe IV : édentation antérieure unique qui traverse la ligne médiane (inclut les deux secteurs antérieurs). Elle est placée AVANT les sous-classes. Particularité : la classe IV n'admet PAS de subdivisions (règle d'Applegate n°5).",tags:["Prothèse amovible","Kennedy","Classe IV","Édentement antérieur"]},
  {id:"pd_k6",prompt:"Les subdivisions dans la classification de Kennedy (ex : classe III subdivision 1) indiquent :",choices:["Le nombre de dents absentes dans la zone principale","La présence d'un ou plusieurs édentements intercalaires supplémentaires en plus de l'édentement principal","Le stade parodontal","La classe d'Angle du patient"],answer:1,diff:2,explication:"Subdivisions : chaque édentement encastré supplémentaire (en dehors de la zone principale de classement) ajoute une subdivision. Classe III subdiv. 1 = un édentement encastré supplémentaire. Les classes I et II peuvent aussi avoir des subdivisions.",tags:["Prothèse amovible","Kennedy","Subdivision","Classification"]},
  {id:"pd_k7",prompt:"La règle d'Applegate stipule que la classification doit être déterminée :",choices:["Avant toute extraction prévue","Après toutes les extractions prévues (pour tenir compte des modifications à venir)","Sur la base du panoramique uniquement","Avant la prise d'empreinte préliminaire"],answer:1,diff:2,explication:"Règle d'Applegate n°1 : la classification se fait APRÈS les extractions prévues. Si une dent présente devra être extraite avant la réalisation de la prothèse, la classification finale doit en tenir compte dès le diagnostic.",tags:["Prothèse amovible","Kennedy","Applegate","Règles"]},
  {id:"pd_k8",prompt:"La classe V d'Applegate (ajout aux classes de Kennedy) correspond à :",choices:["Un édentement total","Un édentement encastré incluant la perte de la canine (modifiant l'appui et le support)","Un édentement postérieur terminal bilatéral avec canine absente","Un édentement antérieur de plus de 4 dents"],answer:1,diff:3,explication:"Classe V d'Applegate : édentement encastré incluant la canine. La perte de la canine modifie le support antérieur de la prothèse. La canine est un pivot essentiel pour l'appui dento-parodontal, d'où la nécessité d'une classe distincte.",tags:["Prothèse amovible","Applegate","Classe V","Canine"]},
  {id:"pd_k9",prompt:"Dans une PAP classe I de Kennedy, les crochets semi-rigides sont utilisés car :",choices:["Ils sont moins coûteux","Ils permettent une rotation/pivotement de la selle sur son axe, absorbant les forces occlusales en flexion plutôt que de les transmettre rigidement aux dents piliers","Ils offrent une meilleure rétention","Ils sont plus esthétiques"],answer:1,diff:2,explication:"Édentement terminal (classe I et II) : la selle repose à la fois sur la muqueuse (compressible) et les dents piliers. Le crochet semi-rigide (à appui indirect sur taquet) autorise un mouvement de rotation autour de l'axe des taquets → dissipe les contraintes. Crochet rigide → surcharge parodontale.",tags:["Prothèse amovible","Kennedy","Crochet semi-rigide","Biomécanique"]},
  {id:"pd_k10",prompt:"La classe III de Kennedy bénéficie de crochets rigides car :",choices:["Elle est moins fréquente","L'édentement encastré est soutenu par des dents des deux côtés → appui dento-parodontal pur, sans dépression muqueuse différentielle","Les crochets rigides sont moins coûteux","La classe III concerne toujours des dents antérieures"],answer:1,diff:2,explication:"Classe III (encastré) : les deux extrémités de l'édentement sont dentées → la selle est stabilisée des deux côtés. Pas de mouvement de rotation → crochets rigides acceptables, transmettant les forces directement aux piliers sans risque de basculement.",tags:["Prothèse amovible","Kennedy","Classe III","Crochet rigide"]},
  {id:"pd_k11",prompt:"Quelle est la classe de Kennedy la plus fréquemment rencontrée en clinique ?",choices:["Classe I","Classe II","Classe III","Classe IV"],answer:2,diff:2,explication:"La classe III (édentement encastré unilatéral) est la plus fréquente en pratique clinique. Elle représente généralement plus de 50% des édentements partiels selon les études épidémiologiques, devant la classe II, puis la classe I, et enfin la classe IV.",tags:["Prothèse amovible","Kennedy","Épidémiologie","Fréquence"]},
  {id:"pd_k12",prompt:"Selon la classification de Kennedy-Applegate, un patient ayant perdu les dents 36, 37, 46 et 47 (molaires inférieures des deux côtés) est en :",choices:["Classe III","Classe II subdivision 1","Classe I","Classe IV"],answer:2,diff:2,explication:"Perte des 4 molaires inférieures des deux côtés → édentation bilatérale postérieure terminale (pas de dents distales de chaque côté) → Classe I de Kennedy. Pas de subdivision car il n'y a pas d'autre édentement encastré supplémentaire.",tags:["Prothèse amovible","Kennedy","Classe I","Application clinique"]},
];

export const QB_PD_SCI2024 = [
  {id:"pd_s1",prompt:"La PAE (Pellicule Acquise Exogène) est :",choices:["Une couche d'émail sur la surface dentaire","Une pellicule salivaire se formant spontanément sur les surfaces dentaires et favorisant l'adhésion bactérienne","Un antibiotique utilisé pour traiter les caries","Un colorant révélateur de plaque"],answer:1,diff:1,explication:"La PAE est une fine pellicule de protéines salivaires (mucines, glycoprotéines) qui se dépose spontanément sur toutes les surfaces buccales. Elle constitue le point d'ancrage des premiers colonisateurs bactériens du biofilm dentaire.",tags:["Biofilm dentaire","PAE","Pellicule acquise exogène","Microbiologie buccale"]},
  {id:"pd_s2",prompt:"Les colonisateurs PRIMAIRES du biofilm dentaire (plaque) sont principalement :",choices:["Treponema spp. et Porphyromonas gingivalis","Streptococcus spp. (notamment S. mutans et S. sanguis)","Fusobacterium nucleatum","Actinobacillus actinomycetemcomitans"],answer:1,diff:2,explication:"Les colonisateurs primaires s'adhèrent directement à la PAE. Ce sont principalement des Streptocoques (S. mutans, S. oralis, S. sanguis) — aérotolérantes, Gram+. Les colonisateurs secondaires (anaérobies stricts comme Porphyromonas, Treponema) viennent ensuite et s'y agrègent via le quorum sensing.",tags:["Biofilm dentaire","Colonisateurs primaires","Streptococcus","Microbiologie buccale"]},
  {id:"pd_s3",prompt:"La plaque dentaire se différencie du biofilm dentaire par :",choices:["Sa composition en bactéries anaérobies uniquement","Sa minéralisation par les sels salivaires (calcifications de phosphate de calcium)","Son adhérence à la gencive uniquement","Sa formation sans matrice polysaccharidique"],answer:1,diff:2,explication:"Le biofilm dentaire = communauté bactérienne dans matrice EPS (exopolysaccharides). La plaque dentaire = biofilm MINÉRALISÉ par les sels de calcium et phosphate salivaires. Cette minéralisation crée le tartre (calculus), favorable aux pathologies parodontales.",tags:["Plaque dentaire","Biofilm","Minéralisation","Tartre"]},
  {id:"pd_s4",prompt:"Le mécanisme de la cariogenèse implique principalement :",choices:["Une erosion mécanique de l'émail par le brossage","La production d'acides organiques (acide lactique) par les bactéries cariogènes → déminéralisation de l'émail (hydroxyapatite)","Une infection virale du tissu dentinaire","Une réaction allergique aux matériaux dentaires"],answer:1,diff:2,explication:"Cariogenèse : sucres alimentaires → fermentation par S. mutans (et Lactobacillus) → acides organiques (lactique, acétique) → pH < 5.5 → dissolution de l'hydroxyapatite (HA) de l'émail. Progression : émail → dentine → pulpite → abcès si non traité.",tags:["Cariogenèse","S. mutans","Acide lactique","Déminéralisation"]},
  {id:"pd_s5",prompt:"La différence entre un désinfectant bactéricide et bactériostatique est :",choices:["Le bactéricide inhibe la croissance ; le bactériostatique tue les bactéries","Le bactéricide tue les bactéries ; le bactériostatique inhibe leur multiplication sans les tuer","Les deux termes sont synonymes","Le bactéricide est utilisé sur les surfaces ; le bactériostatique sur la peau"],answer:1,diff:1,explication:"Bactéricide = destruction irréversible des bactéries (ex : hypochlorite de sodium, aldéhydes). Bactériostatique = inhibition réversible de la multiplication (ex : certains antibiotiques, concentrations faibles de désinfectants). En désinfection laboratoire dentaire, on utilise des produits bactéricides.",tags:["Bactéricide","Bactériostatique","Désinfection","Microbiologie"]},
  {id:"pd_s6",prompt:"Les 4 phases de la courbe de croissance bactérienne en milieu fermé sont dans l'ordre :",choices:["Exponentielle → latence → stationnaire → déclin","Latence → exponentielle (logarithmique) → stationnaire → déclin (mort)","Stationnaire → latence → exponentielle → déclin","Latence → stationnaire → exponentielle → déclin"],answer:1,diff:1,explication:"Phase A (latence) : adaptation au milieu, pas de division. Phase B (exponentielle/log) : divisions rapides, doublement régulier. Phase C (stationnaire) : nutriments s'épuisent, nombre naissance = nombre morts. Phase D (déclin/mort) : accumulation déchets + carence → mortalité > naissance.",tags:["Courbe de croissance","Bactéries","Phases","Microbiologie"]},
  {id:"pd_s7",prompt:"L'UFC (Unité Formant Colonie) dans le cadre du dénombrement microbien désigne :",choices:["La quantité de bactéries trop petite pour former une colonie","Une ou plusieurs cellules bactériennes à l'origine d'une colonie visible sur un milieu gélosé","Le nombre total de bactéries mortes et vivantes","L'unité de mesure de la biomasse bactérienne"],answer:1,diff:1,explication:"L'UFC (ou CFU : Colony Forming Unit) = quantité de microorganismes capables de former une colonie visible sur milieu gélosé. Peut correspondre à 1 cellule ou à un amas de cellules non dissocié. Le résultat s'exprime en UFC/mL ou UFC/g. Dénombrement en surface (étalement) ou en profondeur (incorporation).",tags:["UFC","Dénombrement","Microbiologie","Bactériologie"]},
  {id:"pd_s8",prompt:"Les normes microbiologiques de l'eau des unités dentaires en milieu hospitalier sont :",choices:["< 10 000 UFC/mL à 37°C","< 100 UFC/mL à 37°C et < 10 UFC/mL à 22°C","< 1 UFC/mL à toutes températures","< 500 UFC/mL à 22°C uniquement"],answer:1,diff:2,explication:"Pour les services de chirurgie dentaire/hospitaliers : eau doit respecter < 100 UFC/mL à 37°C (flore pathogène potentielle) et < 10 UFC/mL à 22°C (flore environnementale totale). L'eau des tubulures non traitée peut atteindre 10⁴-10⁵ UFC/mL → risque infectieux majeur.",tags:["Eau unités dentaires","Normes microbiologiques","UFC","Désinfection eau"]},
  {id:"pd_s9",prompt:"Les microorganismes potentiellement pathogènes identifiés dans les eaux non traitées des tubulures des unités dentaires incluent :",choices:["Streptococcus mutans et Lactobacillus spp.","Pseudomonas aeruginosa et Legionella spp.","Candida albicans uniquement","Staphylococcus aureus et E. coli"],answer:1,diff:2,explication:"P. aeruginosa (Gram-, opportuniste, risque chez immunodéprimés) et Legionella spp. (agent de la légionellose / maladie du légionnaire) se développent dans les biofilms des tubulures. Ces bactéries aérosol-transmises lors de l'utilisation des instruments à eau (seringues air-eau, turbines) représentent un risque infectieux documenté.",tags:["Pseudomonas aeruginosa","Legionella","Eau dentaire","Biofilm tubulures"]},
  {id:"pd_s10",prompt:"L'OPG (Orthopantomogramme) est une technique d'imagerie dentaire qui permet :",choices:["Une vue intra-buccale d'une seule dent en 2D","Une radiographie panoramique extraorale de l'ensemble de la dentition et des maxillaires en une seule image","Un examen tridimensionnel de l'os alvéolaire","Une IRM (Imagerie par Résonance Magnétique) des tissus mous"],answer:1,diff:1,explication:"L'OPG (aussi appelé OPT) est une radiographie extra-orale panoramique. Elle permet de visualiser l'ensemble de la denture supérieure et inférieure, les maxillaires, l'ATM, les sinus et les germes des dents de sagesse. Indispensable en implantologie pour le bilan pré-opératoire.",tags:["OPG","Orthopantomogramme","Imagerie dentaire","Radiographie"]},
  {id:"pd_s11",prompt:"Le Cone Beam (CBCT — Cone Beam Computed Tomography) présente l'avantage principal par rapport à l'OPG d'être :",choices:["Moins irradiant et en noir et blanc","Tridimensionnel (3D) avec reconstitutions multi-planaires, permettant de mesurer précisément l'os alvéolaire","Une technique uniquement pour les enfants","Une technique de fluorescence pour détecter les caries"],answer:1,diff:2,explication:"Le CBCT (Cone Beam) produit des images 3D de haute résolution avec moins d'irradiation qu'un scanner médical. Indispensable en implantologie (mesure hauteur/largeur osseuse, localisation nerf alvéolaire inférieur), en orthodontie (analyse céphalométrique 3D), en endodontie complexe. Coupe axiale, coronale, sagittale possibles.",tags:["Cone Beam","CBCT","Imagerie 3D","Implantologie","Radiologie dentaire"]},
  {id:"pd_s12",prompt:"L'indice de polymérisation (n) d'un polymère est calculé par :",choices:["n = masse molaire du monomère / masse molaire du polymère","n = masse molaire du polymère / masse molaire du monomère","n = nombre d'atomes de carbone du monomère","n = degré d'insaturation de la molécule de base"],answer:1,diff:2,explication:"Indice de polymérisation n = Mmol(polymère) / Mmol(monomère). Ex : polystyrène de masse 280 800 g/mol, styrène = 104 g/mol → n = 280 800 / 104 = 2700. Plus n est grand, plus les chaînes sont longues et plus le matériau est résistant. En prothèse dentaire, le PMMA (polyméthacrylate de méthyle) est le principal polymère utilisé pour les bases de prothèses amovibles.",tags:["Polymérisation","Indice de polymérisation","PMMA","Polystyrène","Chimie des polymères"]},
];

// ─── BANQUE QB_PD_IMPLANTS ───
export const QB_PD_IMPLANTS = [
  {id:"pd_im1",prompt:"Un implant dentaire est principalement défini comme :",choices:["Une dent artificielle en céramique collée sur la gencive","Une vis en titane (grade 4 ou alliage Ti-6Al-4V) ostéo-intégrée dans l'os alvéolaire, décrite par Brånemark en 1952","Une prothèse amovible ancrée sur des crochets","Un bridge fixé sur des dents naturelles adjacentes"],answer:1,diff:1,explication:"L'implant dentaire est une vis en titane pur (grade 4) ou en alliage Ti-6Al-4V (grade 5) insérée chirurgicalement dans l'os alvéolaire. Per-Ingvar Brånemark (1952) a décrit pour la première fois le phénomène d'ostéo-intégration après avoir observé que le titane se liait directement à l'os sans tissu interposé.",tags:["Implant","Titane","Brånemark","Définition"]},
  {id:"pd_im2",prompt:"L'ostéo-intégration est définie comme :",choices:["La cicatrisation gingivale autour de l'implant","Une ankylose fonctionnelle directe entre l'os vivant et la surface de l'implant, sans tissu fibreux interposé","La formation d'un tissu conjonctif autour de la vis implantaire","Le remodelage osseux uniquement après fracture"],answer:1,diff:2,explication:"L'ostéo-intégration (Brånemark) = contact direct os-implant sans tissu fibreux ou cartilagineux interposé. Conditions nécessaires : stabilité primaire suffisante, biocompatibilité du titane (couche d'oxyde TiO₂), absence d'infection, charge progressive. Phase de consolidation : 3 à 6 mois selon la qualité osseuse.",tags:["Ostéo-intégration","Implant","Brånemark","Biocompatibilité"]},
  {id:"pd_im3",prompt:"Parmi les contre-indications ABSOLUES à la pose d'implants dentaires, on trouve :",choices:["L'âge supérieur à 60 ans et l'hypertension traitée","La radiothérapie cervico-faciale récente, les bisphosphonates IV et le diabète non équilibré","Le tabagisme modéré et la grossesse au 2ème trimestre","L'édentation totale et les allergies alimentaires"],answer:1,diff:2,explication:"Contre-indications absolues : radiothérapie cervico-faciale récente (risque d'ostéoradionécrose), bisphosphonates intraveineux (ostéonécrose des mâchoires), diabète non équilibré (cicatrisation altérée), thrombopénie grave. Le tabagisme excessif est une contre-indication relative (risque d'échec multiplié par 2-3).",tags:["Implant","Contre-indications","Ostéoradionécrose","Bisphosphonates"]},
  {id:"pd_im4",prompt:"Les étapes chirurgicales de la pose d'un implant dentaire sont, dans l'ordre :",choices:["Pose du pilier → forage osseux → cicatrisation → implant","Forage osseux progressif (fraises croissantes + irrigation) → mise en place implant → suture → cicatrisation 3-6 mois → mise en charge prothétique","Empreinte → forage → implant → couronne immédiate dans tous les cas","Anesthésie → extraire la dent → poser l'implant sans attente"],answer:1,diff:2,explication:"Protocole standard en 2 temps chirurgicaux : (1) forage osseux avec fraises de diamètres croissants sous irrigation sérum physiologique, (2) vissage de l'implant au couple prescrit, (3) suture + cicatrisation osseuse péri-implantaire (ossification : 3 mois mandibule / 6 mois maxillaire), (4) dégagement de l'implant + pose du pilier, (5) prothèse définitive.",tags:["Implant","Chirurgie","Protocole","Forage"]},
  {id:"pd_im5",prompt:"La stabilité primaire d'un implant est :",choices:["La stabilité obtenue uniquement après 6 mois d'ostéo-intégration","L'ancrage mécanique immédiat lors de la pose, évaluée par le couple d'insertion (N·cm) ou le quotient de stabilité ISQ","La résistance à l'arrachement obtenue grâce aux crochets de rétention","La solidité de la couronne définitive sur le pilier"],answer:1,diff:2,explication:"La stabilité primaire = ancrage mécanique immédiat (compression os-implant lors du vissage). Elle est mesurée par le couple d'insertion (Nm) ou la fréquence de résonance (ISQ : Implant Stability Quotient, 1-100). Un ISQ > 65 est considéré comme une bonne stabilité. Elle conditionne la possibilité de charge immédiate.",tags:["Implant","Stabilité primaire","ISQ","Couple d'insertion"]},
  {id:"pd_im6",prompt:"La connexion morse taper (cône morse) entre un implant et son pilier se caractérise par :",choices:["Un hexagone externe saillant sur l'implant","Un frottement conique précis (11-16°) assurant une étanchéité bactérienne supérieure à l'hexagone externe","Un filetage interne standard sans précision angulaire","Un attachement magnétique"],answer:1,diff:3,explication:"Connexions implant-pilier : hexagone externe (classique Brånemark, simple), hexagone interne (meilleure résistance), cône morse (morse taper) : connexion conique par frottement (angle 11-16°) → hautement précis, étanchéité bactérienne excellente (microgap minimal), résistance aux forces latérales supérieure. Standard de référence actuel.",tags:["Implant","Connexion morse","Pilier implantaire","Hexagone"]},
  {id:"pd_im7",prompt:"Le protocole prothétique d'une couronne unitaire implanto-portée comprend :",choices:["Directement une couronne collée sur l'implant","Pilier individualisé (titane ou zircone) → empreinte ou scan → couronne (zircone, e.max ou CCM) vissée ou collée sur le pilier","Uniquement une couronne en résine vissée à vie","Un bridge sur 3 implants obligatoirement"],answer:1,diff:2,explication:"Restauration unitaire sur implant : (1) pilier individualisé anatomique (titane usiné ou zircone) vissé sur l'implant, (2) empreinte physique ou scan numérique, (3) fabrication de la couronne (zircone, IPS e.max, CCM selon localisation/esthétique), (4) assemblage : vissage trans-palatin ou collage sur pilier.",tags:["Implant","Couronne implanto-portée","Pilier","Prothèse fixée"]},
  {id:"pd_im8",prompt:"La technique All-on-4 pour une arcade complète utilise :",choices:["8 implants axiaux répartis sur l'arcade","2 implants axiaux antérieurs + 2 implants postérieurs inclinés à 30-45° pour éviter les sinus, supportant un bridge complet","4 implants centraux uniquement avec overdenture","6 implants verticaux sans inclinaison"],answer:1,diff:2,explication:"All-on-4 (Malo, Nobel Biocare) : 2 implants antérieurs axiaux + 2 implants postérieurs inclinés 30-45° (pour éviter les cavités sinusiennes au maxillaire). Charge immédiate d'un bridge complet vissé sur les 4 implants. Avantage : évite la greffe osseuse dans la majorité des cas.",tags:["Implant","All-on-4","Bridge complet","Charge immédiate"]},
  {id:"pd_im9",prompt:"Une overdenture sur implants est :",choices:["Une prothèse fixée non déposable","Une prothèse amovible stabilisée par 2-4 implants via des attachements (boule, Locator, magnétique), offrant une meilleure rétention qu'une PAC conventionnelle","Un bridge implanto-porté complet","Une prothèse partielle sur crochets"],answer:1,diff:1,explication:"Overdenture = prothèse amovible complète ou partielle RETENUE par des implants. Attachements : boule (sphérique), Locator (nylon + angulation compensée), magnétique (rétention par aimants), barre (Dolder/Hader). 2 implants minimum à la mandibule = standard de soins (consensus McGill 2002). Améliore masication, rétention, qualité de vie.",tags:["Implant","Overdenture","Attachement","Locator"]},
  {id:"pd_im10",prompt:"La péri-implantite est définie comme :",choices:["Une simple sensibilité post-opératoire de l'implant après la pose","Une infection inflammatoire du tissu péri-implantaire avec destruction osseuse, équivalent de la parodontite","Un rejet de l'implant par allergie au titane","Une fracture de l'implant sous charge excessive"],answer:1,diff:2,explication:"Péri-implantite : inflammation chronique des tissus mous et durs péri-implantaires → destruction osseuse péri-implantaire (analogue à la parodontite). Facteurs de risque : hygiène insuffisante, tabac, diabète, antécédents de parodontite. Traitement : débridement mécanique + antibiotiques locaux/systémiques ± chirurgie résective ou régénérative.",tags:["Implant","Péri-implantite","Infection","Parodontite"]},
  {id:"pd_im11",prompt:"La charge immédiate d'un implant (prothèse provisoire dans les 48h) est possible si :",choices:["L'ISQ est supérieur à 40 et le patient est non-fumeur","L'ISQ ≥ 70 ET le couple d'insertion ≥ 35 N·cm, assurant une stabilité primaire suffisante","La charge immédiate est toujours possible sans conditions","Le patient a moins de 50 ans et pas de diabète"],answer:1,diff:3,explication:"Charge immédiate : provisoire posée dans les 48h suivant la chirurgie. Critères : ISQ ≥ 70, couple d'insertion ≥ 35 N·cm (stabilité primaire excellente), os de bonne qualité (type I/II), protocole strict (mise hors occlusion). Si stabilité insuffisante → risque d'échec d'ostéo-intégration par micromouvements > 100 µm.",tags:["Implant","Charge immédiate","ISQ","Stabilité primaire"]},
  {id:"pd_im12",prompt:"Les matériaux de greffe osseuse utilisés en implantologie lorsque le volume osseux est insuffisant comprennent :",choices:["Uniquement l'os autologue (prélèvement sur le même patient)","Os autologue (référence), xénogreffe (os bovin déprotéiné Bio-Oss), matériaux alloplastiques (HA synthétique, β-TCP) et membranes résorbables (GBR)","Uniquement les membranes synthétiques non résorbables","L'hydroxyapatite uniquement pour les sinus lift"],answer:1,diff:2,explication:"Greffe osseuse péri-implantaire : (1) Os autologue (gold standard, prélèvement symphyse mentonnière, ramus, crête iliaque), (2) Xénogreffe bovine déprotéinée (Bio-Oss, Geistlich), (3) Alloplastiques synthétiques (HA, β-TCP résorbable, bioverres), (4) GBR (Guided Bone Regeneration) : membrane résorbable (collagène) ou non résorbable (PTFE-e) pour guider la régénération.",tags:["Implant","Greffe osseuse","Bio-Oss","GBR","Xénogreffe"]},
];

// ─── BANQUE QB_PD_OCCLUSION ───
export const QB_PD_OCCLUSION = [
  {id:"pd_oc1",prompt:"L'occlusion d'intercuspidation maximale (OIM) est définie comme :",choices:["La position mandibulaire avec les condyles en position haute dans les fosses glénoïdes","La position de maximum de contacts dento-dentaires, utilisée comme référence clinique principale","La position de la mandibule lors de la déglutition uniquement","La position de repos mandibulaire (espace libre)"],answer:1,diff:1,explication:"L'OIM (anciennement PIM : position d'intercuspidation maximale) = position de référence clinique avec le plus grand nombre de contacts dentaires simultanés. Utilisée pour l'examen de l'occlusion, la fabrication des prothèses et le contrôle de l'occlusion. N'est pas toujours coïncidente avec la relation centrée (RC).",tags:["Occlusion","OIM","Intercuspidation maximale","Référence clinique"]},
  {id:"pd_oc2",prompt:"La relation centrée (RC) en prothèse est définie comme :",choices:["La position de l'OIM chez tous les patients","La position mandibulaire reproductible avec les condyles en position haute et antérieure dans les fosses glénoïdes, disques bien positionnés","La position mandibulaire de repos (bouche entrouverte)","La position en bout à bout incisif"],answer:1,diff:2,explication:"La RC (Dawson/Roth) = position articulaire de référence physiologique, reproductible. Condyles en position musculo-squelettale stable : haute, antérieure, médiale dans les fosses glénoïdes. Disques articulaires correctement interposés. Base des réhabilitations prothétiques complètes et de l'orthodontie orthopédique.",tags:["Occlusion","Relation centrée","RC","Condyle","Prothèse"]},
  {id:"pd_oc3",prompt:"Chez la majorité des patients (95%), la déviation entre OIM et RC est :",choices:["Supérieure à 5 mm et toujours pathologique","De quelques dixièmes à quelques millimètres, non pathologique si < 1.5 mm et sans symptôme ATM","Nulle (OIM = RC) dans 95% des cas","Toujours de 3 mm exactement"],answer:1,diff:2,explication:"95% des patients sains présentent une déviation OIM-RC (glissement en propulsion de quelques dixièmes à 1-2 mm). Ce déplacement est physiologique s'il est < 1.5 mm, sans asymétrie marquée, et sans signes de dysfonction ATM (douleurs, craquements, limitation). Au-delà ou avec symptômes → bilan approfondi nécessaire.",tags:["Occlusion","OIM","RC","Déviation","Physiologie"]},
  {id:"pd_oc4",prompt:"Le guide antérieur dans le schéma occlusal a pour rôle principal :",choices:["D'augmenter les forces de mastication sur les molaires","D'assurer la désocclusion des dents postérieures lors des mouvements de propulsion et de latéralité, protégeant les cuspides","De servir d'ancrage pour les prothèses amovibles","D'aligner les dents antérieures uniquement pour l'esthétique"],answer:1,diff:2,explication:"Guide antérieur = contact des dents antérieures (incisives, canines) lors des mouvements excursifs. En propulsion : contacts incisifs → désocclusion postérieure (protection des cuspides postérieures). En latéralité : guidage canin (idéal) ou fonction de groupe. Reconstruction du guide antérieur = priorité en réhabilitation prothétique globale.",tags:["Occlusion","Guide antérieur","Désocclusion","Cuspides"]},
  {id:"pd_oc5",prompt:"La courbe de Spee est :",choices:["Une courbure occlusale frontale (médio-latérale) des prémolaires et molaires","Une courbure occlusale sagittale (antéro-postérieure), concave vers le haut en vue de profil, influençant la guidance en propulsion","Une ligne droite reliant les pointes des cuspides","La courbe palatine des incisives"],answer:1,diff:2,explication:"Courbe de Spee (1890) : courbure dans le plan sagittal reliant le bord incisif des incisives aux pointes des cuspides distales des molaires. Concave vers le haut (vue sagittale). Elle est liée à la pente condylienne et au guide antérieur. Aplatissement de la courbe de Spee = indication de traitement orthodontique.",tags:["Occlusion","Courbe de Spee","Sagittale","Propulsion"]},
  {id:"pd_oc6",prompt:"La courbe de Wilson (courbure occlusale frontale) correspond à :",choices:["La courbe antéro-postérieure des dents dans le plan sagittal","La courbure médio-latérale dans le plan frontal : les cuspides linguales sont plus basses que les vestibulaires au maxillaire, influençant la guidance en latéralité","Une courbe verticale de l'os alvéolaire","La courbure gingivale des secteurs postérieurs"],answer:1,diff:3,explication:"Courbe de Wilson : courbure dans le plan frontal reliant les cuspides vestibulaires et linguales des dents postérieures. Au maxillaire : cuspides palatines plus basses → concavité vers le haut. À la mandibule : concavité vers le bas. Avec la courbe de Spee, elle définit la sphère de Monson (surface sphérique d'occlusion).",tags:["Occlusion","Courbe de Wilson","Frontale","Latéralité"]},
  {id:"pd_oc7",prompt:"Les troubles temporo-mandibulaires (TTM / SADAM) regroupent :",choices:["Uniquement les fractures condyliennes","Les douleurs ATM, craquements articulaires et limitation d'ouverture buccale, d'étiologie multifactorielle (stress, bruxisme, malocclusion)","Uniquement les caries et les parodontites","Les infections post-opératoires implantaires"],answer:1,diff:1,explication:"TTM (anciennement SADAM : Syndrome Algo-Dysfonctionnel de l'Appareil Manducateur) : troubles musculo-articulaires de l'ATM. Symptômes : douleurs péri-articulaires ou musculaires, craquements/claquements, limitation d'ouverture (< 35 mm = limitation clinique). Traitement initial : gouttière occlusale, kinésithérapie, anxiolytiques. Chirurgie en dernier recours.",tags:["TTM","SADAM","ATM","Douleur","Bruxisme"]},
  {id:"pd_oc8",prompt:"Le bruxisme dentaire est défini comme :",choices:["Une maladie infectieuse des gencives","Une parafonction de grincement (bruxisme excentrique) ou serrement (bruxisme centrique) des dents, nocturne ou éveillé","Un trouble de la déglutition","Une malocclusion de classe II d'Angle"],answer:1,diff:1,explication:"Bruxisme : activité répétitive des muscles masticateurs (grincement excentrique / serrement centrique). Bruxisme du sommeil (SB) : mouvements rythmiques des muscles masticateurs pendant le sommeil. Conséquences : usure dentaire, fractures, hypertrophie masséterine, TTM. Traitement : gouttière Michigan (déprogrammation + protection), thérapie comportementale.",tags:["Bruxisme","Parafonction","Gouttière Michigan","ATM"]},
  {id:"pd_oc9",prompt:"Un articulateur semi-adaptable permet :",choices:["Uniquement l'ouverture et la fermeture de la bouche artificielle","De reproduire les mouvements mandibulaires avec les paramètres individuels du patient (pente condylienne, angle de Bennett) grâce à l'arc facial et aux enregistrements occlusaux","D'usiner directement des couronnes en zircone","De simuler uniquement la déglutition"],answer:1,diff:2,explication:"Articulateur semi-adaptable (Quick Master, Artex, SAM) : réglage de la pente condylienne (propulsion) et de l'angle de Bennett (latéralité) selon les paramètres du patient. Nécessite : arc facial (position du maxillaire/axe charnière) + enregistrements RC + enregistrements de latéralité. Indispensable pour les réhabilitations occlusales et les PAC.",tags:["Articulateur","Semi-adaptable","Pente condylienne","Bennett"]},
  {id:"pd_oc10",prompt:"L'arc facial est utilisé pour :",choices:["Mesurer la profondeur des poches parodontales","Enregistrer la position des maxillaires par rapport à l'axe charnière condylien, permettant le montage du modèle maxillaire en position correcte sur l'articulateur","Prendre l'empreinte de précision des préparations","Déterminer la teinte des dents prothétiques"],answer:1,diff:2,explication:"L'arc facial (kinematic face bow) enregistre la position tridimensionnelle du maxillaire par rapport à l'axe charnière (axe de rotation des condyles). Il est ensuite transféré sur l'articulateur pour un montage physiologiquement correct. Sans arc facial, le montage est arbitraire et peut induire des erreurs occlusales.",tags:["Arc facial","Articulateur","Axe charnière","Montage"]},
  {id:"pd_oc11",prompt:"L'enregistrement occlusal en A-silicone pour le montage sur articulateur est préféré car :",choices:["Il est moins coûteux que la cire","Il offre une stabilité dimensionnelle supérieure et une précision accrue par rapport à la cire d'occlusion (pas de déformation thermique)","Il est plus rapide que le plâtre","Il peut être réutilisé pour plusieurs montages"],answer:1,diff:2,explication:"Enregistrements occlusaux : cire d'occlusion (économique, risque de déformation thermique), résine bis-acryl ou A-silicone (précision, stabilité dimensionnelle, rigidité après prise). L'A-silicone (polyvinylsiloxane) est le gold standard actuel pour les enregistrements de RC, OIM et latéralités destinés à un articulateur semi-adaptable.",tags:["Enregistrement occlusal","A-silicone","Articulateur","RC"]},
  {id:"pd_oc12",prompt:"Le schéma de Posselt représente :",choices:["La répartition des contacts occlusaux en OIM uniquement","L'ensemble des mouvements possibles de la mandibule (mouvements bordants) en vue sagittale ou frontale, délimitant l'espace fonctionnel mandibulaire","La courbe de croissance osseuse condylienne","Le trajet condylien lors de la propulsion uniquement"],answer:1,diff:3,explication:"Diagramme de Posselt (1952) : représentation graphique (arabesque) de tous les mouvements mandibulaires extrêmes (bordants) en vue sagittale et frontale. Il délimite l'enveloppe des mouvements. Points repère : RC, OIM, position de repos, propulsion maximale, latéralités. Utilisé pour l'analyse cinématique mandibulaire.",tags:["Posselt","Mouvements mandibulaires","Occlusion","Cinématique"]},
];

// ─── BANQUE QB_PD_GESTION_LAB ───
export const QB_PD_GESTION_LAB = [
  {id:"pd_gl1",prompt:"Le bon de travail (prescription) accompagnant une prothèse dentaire doit obligatoirement contenir :",choices:["Uniquement le nom du patient et la teinte","Identification du patient, du praticien, du laboratoire, description de la prothèse, matériaux, teinte et date de livraison souhaitée","Uniquement le numéro de sécurité sociale et le devis","La signature du patient uniquement"],answer:1,diff:1,explication:"Le bon de travail (BTL) est un document médico-légal obligatoire pour chaque prothèse. Mentions obligatoires (MDR 2017/745) : identité patient, coordonnées praticien prescripteur, coordonnées laboratoire, description détaillée de la prothèse, teinte (VITA), matériaux prescrits, date livraison souhaitée, signature du chirurgien-dentiste.",tags:["Bon de travail","Prescription","MDR","Gestion laboratoire"]},
  {id:"pd_gl2",prompt:"La norme ISO 13485 s'applique aux laboratoires de prothèse car :",choices:["Elle définit les dimensions des instruments médicaux uniquement","C'est la norme de management de la qualité spécifique aux fabricants de dispositifs médicaux, imposant traçabilité, gestion des risques et validation des procédés","Elle concerne uniquement les hôpitaux","Elle est facultative pour les DM sur mesure"],answer:1,diff:2,explication:"ISO 13485 : système de management de la qualité (SMQ) pour les dispositifs médicaux. Exigences clés : documentation exhaustive, gestion des risques (ISO 14971), traçabilité des matériaux et opérations, validation des procédés critiques, contrôle des non-conformités, revue de direction. Certification recommandée (voire exigée) pour les laboratoires soumis au règlement MDR 2017/745.",tags:["ISO 13485","Qualité","Laboratoire","Dispositif médical"]},
  {id:"pd_gl3",prompt:"La traçabilité d'une prothèse dentaire (DM sur mesure classe IIa) impose de conserver les documents pendant :",choices:["2 ans","10 ans minimum (bon de travail, déclaration de conformité, matériaux avec numéros de lots, opérateurs)","1 an","Illimitée"],answer:1,diff:2,explication:"MDR 2017/745, article 10 : les fabricants de DM sur mesure (prothèses dentaires = classe IIa) doivent conserver le dossier technique et la documentation de traçabilité 10 ans après la mise sur le marché. Éléments : bon de travail, déclaration de conformité CE, fiches techniques des matériaux (nom commercial + numéro de lot), opérateurs impliqués.",tags:["Traçabilité","DM sur mesure","MDR","10 ans"]},
  {id:"pd_gl4",prompt:"Le coût de revient d'une prothèse comprend :",choices:["Uniquement les matières premières","Matières premières + main-d'œuvre directe (taux horaire × temps de fabrication) + charges indirectes (amortissements, frais généraux)","Uniquement la main-d'œuvre","Le prix de vente moins la marge"],answer:1,diff:2,explication:"Coût de revient complet (méthode des coûts complets) = charges directes (matières premières + M.O. directe) + charges indirectes (quote-part des amortissements, loyer, énergie, frais généraux). La méthode des coûts variables distingue charges fixes/variables pour l'analyse de la rentabilité.",tags:["Coût de revient","Gestion","Comptabilité","Laboratoire"]},
  {id:"pd_gl5",prompt:"Le seuil de rentabilité (SR) d'un laboratoire de prothèse est calculé par :",choices:["SR = Chiffre d'affaires × Taux de marge","SR = Charges fixes / Taux de marge sur coût variable (TMCV)","SR = Charges variables / Chiffre d'affaires","SR = Résultat net / Charges fixes"],answer:1,diff:3,explication:"SR = Charges fixes / TMCV. TMCV = Marge sur coût variable / CA = (CA - Charges variables) / CA. En dessous du SR : l'entreprise est en perte (les recettes ne couvrent pas toutes les charges fixes). Marge de sécurité = CA réalisé - SR. Index de sécurité = marge de sécurité / CA (exprimé en %).",tags:["Seuil de rentabilité","Gestion","Charges fixes","TMCV"]},
  {id:"pd_gl6",prompt:"La Valeur Ajoutée (VA) dans les Soldes Intermédiaires de Gestion (SIG) représente :",choices:["Le chiffre d'affaires total de l'année","La richesse créée par l'entreprise : Marge brute − Consommations en provenance de tiers (fournitures, services extérieurs)","Le résultat net après impôt","La trésorerie disponible en fin d'exercice"],answer:1,diff:3,explication:"SIG (selon Plan Comptable Général) : Ventes → Marge brute (ventes - coût achat marchandises) → Valeur Ajoutée (MB - consommations externes) → EBE (VA - charges de personnel - impôts et taxes) → Résultat d'exploitation (EBE - dotations aux amortissements) → Résultat courant → Résultat net. La VA mesure la création de richesse propre à l'entreprise.",tags:["SIG","Valeur ajoutée","EBE","Comptabilité"]},
  {id:"pd_gl7",prompt:"La RSE (Responsabilité Sociétale des Entreprises) en laboratoire de prothèse repose sur :",choices:["Uniquement la rentabilité financière du laboratoire","3 piliers : économique (rentabilité durable), social (conditions de travail, diversité) et environnemental (gestion des déchets, énergie, fournisseurs locaux)","Uniquement la conformité réglementaire MDR","L'obligation légale annuelle de publier un rapport RSE"],answer:1,diff:2,explication:"RSE (triple bottom line) : pilier économique (viabilité à long terme), pilier social (bien-être des salariés, non-discrimination, handicap, formation), pilier environnemental (réduction des déchets chimiques/solides, économies d'énergie, circuit court pour matériaux). Démarche volontaire (non obligatoire en PME) mais valorisante commercialement et éthiquement.",tags:["RSE","Développement durable","Gestion","Environnement"]},
  {id:"pd_gl8",prompt:"Les principaux risques professionnels du prothésiste dentaire incluent :",choices:["Uniquement les risques de chutes et coupures","Poussières fines (silice, zircone, PMMA → silicose), bruit (fraiseuses), risques chimiques (monomères MMA allergènes), nécessitant EPI adaptés","Uniquement les risques infectieux biologiques","Les risques de brûlures par les fours uniquement"],answer:1,diff:1,explication:"Risques professionnels spécifiques : (1) Poussières inhalables : zircone (fibrose pulmonaire possible), PMMA, silice cristalline (silicose) → masque FFP2/FFP3 + aspiration. (2) Bruit : fraiseuses MOCN (> 85 dB) → protection auditive. (3) Chimiques : MMA (monomère, allergisant cutané/respiratoire) → gants nitrile, ventilation. (4) Biologiques : empreintes contaminées.",tags:["Risques professionnels","Prothésiste dentaire","EPI","Silicose"]},
  {id:"pd_gl9",prompt:"Le DUERP (Document Unique d'Évaluation des Risques Professionnels) est :",choices:["Un document facultatif pour les grandes entreprises uniquement","Un document obligatoire dès 1 salarié, inventoriant tous les risques (cotation fréquence × gravité) et les mesures préventives, mis à jour annuellement","Une simple liste des EPI disponibles dans le laboratoire","Un bilan financier de la prévention des accidents"],answer:1,diff:2,explication:"DUERP (Code du travail, R4121-1) : obligatoire pour tout employeur (dès 1 salarié). Contenu : inventaire exhaustif des risques par unité de travail, cotation (probabilité × gravité), plan d'action préventif (mesures techniques, organisationnelles, EPI). Mis à jour annuellement et après tout accident du travail.",tags:["DUERP","Risques professionnels","Prévention","Médecine du travail"]},
  {id:"pd_gl10",prompt:"La convention collective nationale des prothésistes dentaires régit notamment :",choices:["Uniquement les tarifs des prothèses","La grille de classification et de salaires, les conditions de travail, la durée du travail, les congés et la formation professionnelle des salariés du secteur","Uniquement les conditions d'hygiène au laboratoire","Les règles de facturation aux chirurgiens-dentistes"],answer:1,diff:1,explication:"La CCN (Convention Collective Nationale) des prothésistes dentaires (IDCC 1996) est un accord collectif de branche qui complète le Code du travail. Elle définit : classifications des emplois (niveaux I-V), grille de salaires minima, conditions de travail, durée légale/aménagement du temps de travail, congés payés, droits à la formation professionnelle (CPF).",tags:["Convention collective","CCN","Prothésiste dentaire","Droit du travail"]},
  {id:"pd_gl11",prompt:"L'amortissement linéaire d'un équipement (ex : imprimante 3D à 12 000 € sur 4 ans) représente par an :",choices:["12 000 € la première année uniquement","3 000 € par an (12 000 / 4), impactant le résultat comptable comme charge sans affecter directement la trésorerie","1 000 € par an","L'amortissement dépend uniquement du CA réalisé"],answer:1,diff:2,explication:"Amortissement linéaire = coût d'acquisition HT / durée de vie comptable. Ici : 12 000 / 4 = 3 000 €/an. L'amortissement est une charge comptable (réduit le résultat = économie fiscale) mais NON une sortie de trésorerie (la trésorerie a été mobilisée lors de l'achat). Il reflète la dépréciation économique de l'actif.",tags:["Amortissement","Comptabilité","Gestion laboratoire","Investissement"]},
  {id:"pd_gl12",prompt:"La différence principale entre SARL et SAS pour un laboratoire de prothèse est :",choices:["La SARL est obligatoire pour les laboratoires de plus de 5 salariés","La SARL a un gérant TNS (travailleur non salarié, RSI/SSI), la SAS a un président assimilé salarié (régime général), et la SAS offre une grande liberté statutaire","Les deux statuts ont le même régime social et fiscal","La SAS est réservée aux laboratoires réalisant plus de 1 M€ de CA"],answer:1,diff:3,explication:"SARL : gérant majoritaire = TNS (cotisations SSI, protection sociale moindre, cotisations inférieures). EURL = version unipersonnelle. SAS/SASU : président = assimilé salarié (régime général SS, meilleure protection, cotisations plus élevées). SAS : grande liberté de rédaction des statuts (intéressant pour les associés multiples). Choix impacte la fiscalité IS/IR et la protection sociale du dirigeant.",tags:["Statut juridique","SARL","SAS","Gestion entreprise"]},
];

// ─── BANQUE QB_PD_CFAO2 ───
export const QB_PD_CFAO2 = [
  {id:"pd_cf1",prompt:"L'empreinte optique intra-orale par scanner intra-buccal (CEREC Primescan, iTero, 3Shape TRIOS) présente comme avantage principal :",choices:["Un coût inférieur aux matériaux d'empreinte conventionnels dans tous les cas","Un meilleur confort patient, l'absence de déformation et une acquisition en temps réel fournissant directement un fichier STL","Une précision systématiquement supérieure aux empreintes A-silicone en tous points","L'absence de formation requise et une utilisation immédiate"],answer:1,diff:2,explication:"Scanner intra-oral : acquisition vidéo/photo 3D en temps réel → fichier STL/PLY transmissible numériquement. Avantages : confort patient (pas de matériau en bouche), pas de déformation (contrairement à alginate/silicone), transmission instantanée au laboratoire. Limites : précision sub-gingivale parfois insuffisante, formation requise, coût d'investissement élevé.",tags:["Empreinte optique","Scanner intra-oral","STL","CFAO"]},
  {id:"pd_cf2",prompt:"exocad est principalement utilisé en CFAO dentaire comme :",choices:["Un logiciel de gestion administrative du laboratoire","Un logiciel CAD (conception assistée par ordinateur) de référence mondiale pour la conception prothétique numérique (couronnes, bridges, châssis, guides chirurgicaux)","Un logiciel de contrôle des fours de frittage","Un logiciel de comptabilité spécialisé pour les laboratoires"],answer:1,diff:1,explication:"exocad (Dentsply Sirona) : logiciel CAD prothétique leader mondial. Modules : couronne/bridge, châssis PAP, implant, orthodontie, wax-up numérique (DDS). Bibliothèques de dents (morphologies), bibliothèques d'implants (connexions). Compatible avec tous les scanners et centres d'usinage. Concurrent principal : 3Shape Dental System (Danemark).",tags:["exocad","CAD","CFAO","Logiciel prothèse"]},
  {id:"pd_cf3",prompt:"Le fraisage MOCN 5 axes pour la zircone utilise des vitesses de rotation de :",choices:["1 000 à 5 000 tr/min (comme un tour conventionnel)","50 000 à 300 000 tr/min (haute vitesse) permettant une précision de ± 20-50 µm","500 tr/min uniquement pour les matériaux durs","10 000 tr/min uniquement"],answer:1,diff:3,explication:"Fraiseuses CFAO dentaire (5 axes, CNC) : broches à haute vitesse 50 000-300 000 tr/min. La haute vitesse est nécessaire pour l'usinage précis de la zircone préfrittée (dure mais usinable), du PMMA, du disque e.max, du titane. Précision dimensionnelle : ± 20-50 µm. Irrigation/aspiration continue pour éviter l'échauffement et les poussières.",tags:["MOCN","Fraisage","Zircone","Vitesse rotation"]},
  {id:"pd_cf4",prompt:"Après fraisage d'un bloc de zircone préfrittée, l'étape de frittage à 1450-1550°C provoque :",choices:["Une expansion de 20-25% du bloc","Un retrait dimensionnel précis de 20-25% (compensé lors de la conception CAD en sur-dimensionnant le projet)","Aucun changement de volume","Un retrait de 50% rendant la pièce inutilisable"],answer:1,diff:2,explication:"Zircone préfrittée (white phase / green body) : poreuse, légère, usinable facilement. Après frittage (1450-1550°C, 2-8h selon le four) : densification complète → retrait de 20-25%. Ce retrait est précis et reproductible → le logiciel CAD sur-dimensionne le projet de 20-25% pour compenser. Résultat : zircone dense ≈ 1200 MPa (3Y-TZP).",tags:["Zircone","Frittage","Retrait","CFAO"]},
  {id:"pd_cf5",prompt:"La zircone haute translucidité (HT, 5Y-PSZ) par rapport à la zircone classique (3Y-TZP) se caractérise par :",choices:["Une résistance mécanique supérieure ET une meilleure translucidité","Une translucidité accrue permettant de réduire ou éliminer le stratifié céramique, mais avec une résistance légèrement inférieure","Des propriétés optiques identiques à la zircone classique","Une couleur plus blanche uniquement"],answer:1,diff:3,explication:"Zircone 3Y-TZP (3 mol% yttria) : résistance élevée (≈ 1200-1400 MPa) mais opaque → nécessite stratification céramique pour l'esthétique. Zircone 5Y-PSZ (5 mol% yttria) : phase cubique dominante → translucidité élevée (comparable à l'e.max) → monolithique possible. Compromis : résistance plus faible (≈ 700-900 MPa). Nano-zircone : grain ultrafin → équilibre translucidité/résistance.",tags:["Zircone","Translucidité","5Y-PSZ","Esthétique"]},
  {id:"pd_cf6",prompt:"L'impression 3D de type SLA/DLP en prothèse dentaire est principalement utilisée pour :",choices:["Usiner directement des couronnes en zircone définitives","Produire des modèles d'étude, guides chirurgicaux implantaires, prothèses provisoires et plaques-bases par photopolymérisation de résines","Fritter les alliages métalliques","Réaliser des châssis PAP en titane par fusion laser"],answer:1,diff:1,explication:"SLA (Stéréolithographie) et DLP (Digital Light Processing) : photopolymérisation de résines liquides par laser UV (SLA) ou projection lumineuse (DLP). Applications dentaires : modèles d'étude (haute résolution, moins cher que plâtre), guides chirurgicaux implantaires, provisoires en PMMA renforcé, plaques-bases de PAC pour essayage. Résines biocompatibles (Classe I/II de biocompatibilité).",tags:["Impression 3D","SLA","DLP","Guides chirurgicaux"]},
  {id:"pd_cf7",prompt:"Le workflow entièrement numérique en prothèse dentaire permet de réduire les délais de fabrication à :",choices:["10-15 jours (identique au workflow conventionnel)","1-2 jours (contre 3-5 jours en workflow conventionnel), grâce à la suppression des étapes physiques d'envoi et de moulage","30 minutes (fabrication immédiate au fauteuil systématiquement)","Uniquement si le cabinet possède une fraiseuse CEREC"],answer:1,diff:2,explication:"Workflow numérique complet : scan intra-oral (cabinet) → transfert STL sécurisé → CAD (laboratoire) → usinage/impression → livraison. Suppression : prise d'empreinte physique, désinfection/envoi empreinte, coulée du modèle en plâtre. Délai réduit : 1-2 jours vs 3-5 jours conventionnel. Avantage additionnel : moins d'allers-retours pour les corrections.",tags:["Workflow numérique","CFAO","Délai","STL"]},
  {id:"pd_cf8",prompt:"Un scanner de bureau (scanner de modèles) se distingue d'un scanner intra-oral par :",choices:["Il est plus précis que le scanner intra-oral dans tous les cas","Il scanne des modèles en plâtre ou des empreintes physiques (hors bouche), est moins coûteux (3-10k€ vs 15-25k€), et offre une précision ≤ 10 µm","Il utilise uniquement des rayons X","Il ne peut pas générer de fichier STL compatible CFAO"],answer:1,diff:2,explication:"Scanner de laboratoire (Dental Wings, 3Shape D2000, Zeiss) : scan les modèles en plâtre ou les empreintes. Précision ≤ 10 µm (supérieure aux scanners intra-oraux dans certaines conditions). Prix : 3 000-10 000 € vs 15 000-25 000 € pour un intra-oral. Compatible logiciels CAD. Solution économique pour les laboratoires qui reçoivent encore des empreintes physiques.",tags:["Scanner de bureau","Modèles plâtre","CFAO","Précision"]},
  {id:"pd_cf9",prompt:"Les portails de communication numérique laboratoire-cabinet (3Shape Communicate, CEREC Connect) permettent :",choices:["Uniquement l'envoi de factures électroniques","L'échange de fichiers STL, de photos cliniques et de consignes de fabrication, réduisant les allers-retours physiques et améliorant la communication interdisciplinaire","Uniquement la gestion des rendez-vous du cabinet dentaire","La facturation directe à la CPAM"],answer:1,diff:1,explication:"Portails numériques (3Shape Communicate, CEREC Connect, Dental Monitoring...) : transfert sécurisé de fichiers STL + photos intra/extra-orales + consignes détaillées (teinte, forme, matériaux). Avantages : réduction du temps d'attente, moins de retours prothétiques, meilleure compréhension des attentes esthétiques. Certains intègrent le DSD (Digital Smile Design).",tags:["Communication numérique","3Shape","CEREC Connect","Laboratoire-cabinet"]},
  {id:"pd_cf10",prompt:"Le contrôle dimensionnel numérique d'une prothèse usinée est réalisé par :",choices:["Une mesure visuelle à la loupe binoculaire uniquement","Scan de la pièce finie + superposition colorisée avec le projet CAD (carte de déviation), ou par machine à mesurer tridimensionnelle (MMT), avec tolérance de 50-100 µm","Un micromètre manuel uniquement","Une comparaison photographique"],answer:1,diff:3,explication:"Contrôle dimensional numérique : scan de la pièce usinée/frittée → alignement numérique sur le fichier CAD d'origine → carte de déviation colorisée (rouge = trop épais, bleu = trop mince). Tolérance acceptable selon norme SSPT (Système de Spécification des Prothèses Tandis) : 50-100 µm selon les zones. MMT (Coordinate Measuring Machine) pour mesures absolues.",tags:["Contrôle dimensionnel","CFAO","Carte de déviation","Qualité"]},
  {id:"pd_cf11",prompt:"Le PEEK (PolyEtherEtherKetone) est utilisé en prothèse dentaire car :",choices:["Il est moins coûteux que le PMMA","Il offre une résistance mécanique élevée (≈ 100 MPa), est biocompatible, et possède un faible module d'élasticité proche de l'os (moins traumatisant pour les structures de soutien)","Il est transparent et esthétique comme la céramique","Il peut être frité comme la zircone"],answer:1,diff:2,explication:"PEEK (PolyEtherEtherKetone) : polymère thermoplastique haute performance. Module d'élasticité ≈ 3-4 GPa (proche de l'os cortical ≈ 18 GPa), résistance à la flexion ≈ 100 MPa, biocompatible. Applications : châssis PAP (alternative au Co-Cr, moins rigide → meilleure transmission des charges à l'os), structures provisoires sur implants. Usinable en CFAO 5 axes.",tags:["PEEK","Prothèse","Biomatériaux","Châssis"]},
  {id:"pd_cf12",prompt:"L'impression 3D métal par fusion sélective par laser (LPBF / SLM) en prothèse dentaire permet :",choices:["Uniquement de produire des modèles en résine métallisée","De produire des châssis PAP, des structures implantaires et des éléments prothétiques complexes en Co-Cr ou titane par fusion d'une poudre métallique couche par couche","D'usiner des blocs de zircone comme une fraiseuse MOCN","De réaliser des empreintes numériques"],answer:1,diff:3,explication:"LPBF (Laser Powder Bed Fusion) / SLM (Selective Laser Melting) : laser haute puissance fusionne couche par couche une poudre métallique (Co-Cr, Ti-6Al-4V). Applications dentaires : châssis PAP (géométries complexes impossibles en coulée centrifuge), couronnes/bridges métalliques, structures implantaires. Avantages : précision ± 50-100 µm, réduction des déchets métalliques, liberté géométrique totale.",tags:["SLM","LPBF","Impression 3D métal","Co-Cr","Châssis PAP"]},
];

// ─── FICHES ───
export const FICHES_PRODENT = [
  {id:"pd_f1",title:"Anatomie dentaire et sciences médico-dentaires",bloc:"Bloc 1",tags:["Anatomie","Dent","Parodonte","Occlusion"],duree:20,niveau:"Fondations",qbank:"pd_sciences",
    contenu:"**Structure dentaire :**\n• Émail : 96% minéral (HAP), tissu le plus dur. Produit par les améloblastes.\n• Dentine : 70% minéral, tubules dentinaires, odontoblastes présents dans la pulpe\n• Pulpe : tissu conjonctif, vaisseaux, nerfs (dentinogénèse continue)\n• Cément : ancrage des fibres de Sharpey (desmodonte)\n\n**Parodonte :** gencive + ligament parodontal + os alvéolaire + cément\n\n**Formule dentaire adulte :** 2.1.2.3 × 4 = 32 dents\nNotation FDI : 11-18, 21-28, 31-38, 41-48\n\n**Occlusion :**\n• Classe I d'Angle : rapport molaire normal (eugnathie)\n• Classe II : décalage distal de la mandibule\n• Classe III : décalage mésial de la mandibule (progénie)\n• Guide antérieur : désocclusion postérieure en propulsion (protection des cuspides)\n\n**ATM :** condyle + fosse glénoïde + disque articulaire"},
  {id:"pd_f2",title:"Biomatériaux dentaires",bloc:"Bloc 2",tags:["Biomatériaux","Céramique","Résine","Alliages","Empreinte"],duree:22,niveau:"Intermédiaire",qbank:"pd_sciences",
    contenu:"**Céramiques :**\n• Feldspathique : translucide, esthétique, fragile (stratification)\n• Disilicate de lithium (e.max) : résistance modérée, translucidité élevée\n• Zircone (YZ) : très résistante (> 1000 MPa), frittage (-20-25%)\n• Zircone multicouche translucide : haute esthétique + résistance\n\n**Alliages :**\n• Or/palladium : métal-céramique (liaisons chimiques optimales)\n• Co-Cr : châssis PAP, couronnes non esthétiques (économique)\n• Titane : implants, châssis CFAO légers\n\n**Résines :**\n• PMMA : provisoires, appareils amovibles (résistance modérée)\n• Composite (BisGMA) : restauration directe/indirecte\n\n**Matériaux d'empreinte :**\n• Alginate : diagnostic, PAP (instable, couler immédiatement)\n• C-silicone : rétraction → moins précis\n• A-silicone : précis, stable (référence PF)\n• Polyéther : très précis, rigide"},
  {id:"pd_f3",title:"CFAO et fabrication numérique",bloc:"Bloc 3",tags:["CFAO","CAD/CAM","Usinage","Impression 3D","Numérique"],duree:20,niveau:"Intermédiaire",qbank:"pd_technique",
    contenu:"**Flux numérique CFAO :**\n1. Acquisition : scanner de laboratoire (modèle) ou empreinte optique (intra-oral) → STL\n2. Conception : logiciel CAD (exocad, 3Shape, Cerec) → fichier de conception\n3. Fabrication : MOCN (fraisage) ou impression 3D\n\n**Fraisage MOCN :**\n• Zircone (préfrittée → sintering 1450-1550°C, retrait 20-25%)\n• PMMA, e.max, titane\n• Précision ± 20-50 µm\n\n**Impression 3D :**\n• SLA : laser UV + résine (haute résolution)\n• DLP : lumière projetée (+ rapide)\n• FDM : filament fondu (moins précis)\n• Applications : maquettes, guides chirurgicaux, gouttières, provisoires\n\n**Avantages :** traçabilité totale, répétabilité, personnalisation, réduction des déchets"},
  {id:"pd_f4",title:"Prothèse fixée : couronne, bridge et collage",bloc:"Bloc 2",tags:["Prothèse fixée","Couronne","Bridge","Collage","Céramique"],duree:22,niveau:"Intermédiaire",qbank:"pd_technique",
    contenu:"**Types de prothèses fixées :**\n• Couronne complète : reconstitue la totalité de la couronne clinique\n• Inlay/onlay : restaurations partielles (intra ou supra-cuspidienne)\n• Bridge : remplace 1+ dent absente (piliers + pontique)\n• Bridge implanto-porté : piliers sur implants\n\n**Matériaux :**\n• Tout-céramique : zircone ou disilicate (esthétique, sans métal)\n• Métal-céramique : CCM (résistant, durée de vie prouvée)\n• Provisoire PMMA (transitoire)\n\n**Protocole collage tout-céramique :**\n1. Mordançage HF (9.5%, 30-60s feldspathique / 20s e.max)\n2. Rinçage + séchage\n3. Silanisation (30s)\n4. Primaire sur la dent + ciment composite dual\n5. Photopolymérisation\n\n**Empreinte de précision :** A-silicone double mélange ou monophasique"},
  {id:"pd_f5",title:"Prothèse amovible : PAP et PAC",bloc:"Bloc 2",tags:["Prothèse amovible","PAP","PAC","Châssis","Édenté"],duree:20,niveau:"Fondations",qbank:"pd_technique",
    contenu:"**Prothèse amovible partielle (PAP) :**\n• Châssis Co-Cr (coulé ou usiné CFAO)\n• Connecteur principal (barre palatine du palais / barre linguale mandibule)\n• Rétentions : crochets (coulés ou fil) + taquets occlusaux\n• Selles : résine + dents prothétiques (résine ou céramique)\n\n**Prothèse amovible complète (PAC) :**\n• Édenté total : repose sur la crête édentée\n• Empreinte anatomique (primaire) + empreinte de joint (secondaire/personnalisée)\n• Plans de référence : plan de Fox, guide antérieur\n• Montage sur articulateur\n• Rétention : aspiration (joint), adhésion, gravité\n\n**Articulateur :**\n• Semi-adaptable : simule les mouvements mandibulaires (arc facial, enregistrement occlusal)\n• Permet un montage précis des dents prothétiques"}
  ,{id:"pd_f7",title:"Classification de Kennedy & Applegate — Édentements partiels",bloc:"Bloc 2",tags:["Prothèse amovible","Kennedy","Applegate","PAP","Classification"],duree:20,niveau:"Intermédiaire",qbank:"pd_kennedy",
    contenu:"**Classification de Kennedy (1925) :**\n\n• **Classe I** : Édentation bilatérale postérieure terminale (libre des deux côtés)\n  → Crochets **semi-rigides** (rotation possible de la selle)\n  → Appui mixte : muco-dento-parodontal\n\n• **Classe II** : Édentation unilatérale postérieure terminale\n  → Côté édenté : crochets **semi-rigides**\n  → Côté denté : crochets **rigides**\n\n• **Classe III** : Édentation unilatérale encastrée (intercalaire)\n  → Crochets **rigides** (appui dento-parodontal pur)\n  → Classe la plus fréquente\n\n• **Classe IV** : Édentation antérieure traversant la ligne médiane\n  → Crochets rigides — **pas de subdivision** (règle Applegate)\n\n**Classes Applegate (complément) :**\n• **Classe V** : Édentation encastrée avec perte de la canine\n• **Classe VI** : Édentation encastrée courte (max 2 dents) pouvant être traitée par bridge\n\n**Subdivisions :**\nChaque édentement encastré supplémentaire (hors zone principale) ajoute une subdivision.\nEx : Classe II Subdivision 1 = 1 édentement encastré supplémentaire.\n\n**Règles d'Applegate (principales) :**\n1. Classer APRÈS les extractions prévues\n2. La 3ème molaire absente sans remplacement → ne pas classer\n3. La 3ème molaire présente comme pilier → inclure\n4. La 2ème molaire absente sans remplacement → ne pas classer\n5. Classe IV = pas de subdivision\n6. L'édentement le plus postérieur détermine la classe\n7. Chaque édentement intercalaire supplémentaire = +1 subdivision\n8. Taille de l'édentement ne modifie pas la classe (mais influence le traitement)"}
  ,{id:"pd_f8",title:"🎓 Annale 2024 E2 — Biofilm dentaire, imagerie & chimie appliquée",bloc:"Bloc 1",tags:["Annale 2024","Biofilm dentaire","Microbiologie buccale","Plaque dentaire","Cariogenèse","OPG","Cone Beam","Polymérisation"],duree:28,niveau:"Avancé",qbank:"pd_sci2024",
    contenu:"**Contexte (E2 Sciences appliquées 2024) :** 3 parties : Anatomie/occlusodontie, Sciences physiques/chimiques, Microbiologie.\n\n**Biofilm dentaire :**\n• Communauté structurée de microorganismes dans une matrice EPS (polysaccharides exocellulaires)\n• Formation : dépôt PAE → colonisateurs primaires (Streptococcus spp.) → quorum sensing → colonisateurs secondaires anaérobies → détachement\n• PAE (Pellicule Acquise Exogène) = pellicule salivaire (protéines, glycoprotéines) → support d'adhésion\n\n**Plaque dentaire & cariogenèse :**\n• Plaque = biofilm MINÉRALISÉ (sels calcium/phosphate salivaires → tartre)\n• Cariogenèse : sucres → fermentation (S. mutans, Lactobacillus) → acides (lactique) → pH < 5.5 → dissolution hydroxyapatite\n• Progression : émail → dentine → pulpite → abcès\n\n**Désinfection :**\n• Bactéricide : tue les bactéries (hypochlorite, glutaraldéhyde)\n• Bactériostatique : inhibe leur multiplication (réversible)\n\n**Courbe de croissance bactérienne :**\n• A = Latence (adaptation) → B = Exponentielle/Log (doublement) → C = Stationnaire (nutriments épuisés) → D = Déclin/Mort\n\n**Eau des unités dentaires :**\n• Normes hospitalières : < 100 UFC/mL à 37°C et < 10 UFC/mL à 22°C\n• Pathogènes potentiels dans tubulures : Pseudomonas aeruginosa, Legionella spp.\n• Dénombrement : UFC = Unité Formant Colonie (colonie visible sur milieu gélosé)\n\n**Imagerie médicale dentaire :**\n• RA (Rétro-Alvéolaire) : intra-buccale, vue d'une dent → caries proximales, parodonte\n• TRP (Téléradiographie de Profil) : squelette facial, céphalométrie orthodontique\n• OPG/OPT : panoramique extraorale → toute la denture, ATM, sinus\n• Cone Beam (CBCT) : 3D → implantologie, endodontie, orthodontie complexe\n\n**Chimie appliquée — Polymères :**\n• Polymérisation par addition : liaison C=C → monomère → polymère (ex : styrène → polystyrène, MMA → PMMA)\n• Polymérisation par condensation : élimination d'un sous-produit (eau, HCl...)\n• Indice de polymérisation n = Mmol(polymère) / Mmol(monomère)\n• Styrène : C₈H₈, Mmol = 104 g/mol. Polystyrène ≈ 280 800 g/mol → n ≈ 2700"}
  ,{id:"pd_f9",title:"Implantologie dentaire : principes, protocoles et complications",bloc:"Bloc 2",tags:["Implant dentaire","Ostéo-intégration","Brånemark","All-on-4","Overdenture","Péri-implantite","Charge immédiate"],duree:24,niveau:"Avancé",qbank:"pd_implants",
    contenu:"**Principes de base :**\n• Implant = vis en titane grade 4 ou Ti-6Al-4V (grade 5) ostéo-intégrée dans l'os alvéolaire\n• Ostéo-intégration (Brånemark, 1952) : contact direct os-implant SANS tissu fibreux interposé\n• Conditions : stabilité primaire suffisante, biocompatibilité TiO₂, absence d'infection, charge progressive\n• Consolidation : 3 mois (mandibule) à 6 mois (maxillaire)\n\n**Contre-indications absolues :**\nRadiothérapie cervico-faciale récente, bisphosphonates IV, diabète non équilibré, thrombopénie grave\n\n**Protocole chirurgical :**\nForage osseux progressif sous irrigation → mise en place implant → suture → cicatrisation → pilier → prothèse\n\n**Stabilité primaire :**\n• ISQ (Implant Stability Quotient) : 1-100 par fréquence de résonance (RFA)\n• Charge immédiate possible si ISQ ≥ 70 ET couple d'insertion ≥ 35 N·cm\n\n**Connexions implant-pilier :**\n• Hexagone externe (classique Brånemark)\n• Cône morse (morse taper) : étanchéité bactérienne supérieure, résistance latérale ↑\n\n**Techniques prothétiques implantaires :**\n• All-on-4 : 2 implants axiaux + 2 inclinés 30-45° → bridge complet (sans greffe dans la majorité des cas)\n• Overdenture : PAC stabilisée par 2-4 implants (attachements boule, Locator, magnétique)\n\n**Complications :**\n• Péri-implantite : infection + destruction osseuse (analogue parodontite)\n• Facteurs de risque : hygiène insuffisante, tabac, diabète, antécédents de parodontite"}
  ,{id:"pd_f10",title:"Occlusodontologie : références, guidances et ATM",bloc:"Bloc 1",tags:["Occlusion","OIM","Relation centrée","Guide antérieur","Courbe de Spee","ATM","Bruxisme","Articulateur","Posselt"],duree:22,niveau:"Avancé",qbank:"pd_occlusion",
    contenu:"**Références occlusales :**\n• OIM (Occlusion d'intercuspidation maximale) : maximum de contacts dento-dentaires → référence clinique principale\n• RC (Relation centrée) : condyles en position haute et antérieure dans les fosses glénoïdes, disques bien positionnés → base des réhabilitations prothétiques\n• Déviation OIM-RC : physiologique si < 1.5 mm et sans symptôme ATM\n\n**Guidances et courbes :**\n• Guide antérieur : désocclusion des dents postérieures en propulsion et latéralité → protection des cuspides\n• Courbe de Spee (sagittale, antéro-postérieure) : concave vers le haut en vue de profil\n• Courbe de Wilson (frontale, médio-latérale) : cuspides palatines plus basses au maxillaire\n• Sphère de Monson : surface sphérique d'occlusion (Spee + Wilson)\n\n**ATM et dysfonctions :**\n• TTM/SADAM : douleurs ATM, craquements, limitation d'ouverture (< 35 mm)\n• Bruxisme : grincement (excentrique) ou serrement (centrique), nocturne ou éveillé\n• Traitement : gouttière Michigan (déprogrammation), kinésithérapie\n\n**Articulateur et enregistrements :**\n• Arc facial : enregistre la position 3D du maxillaire par rapport à l'axe charnière\n• Articulateur semi-adaptable : pente condylienne + angle de Bennett\n• Enregistrement occlusal : A-silicone (gold standard, stable dimensionnellement)\n\n**Schéma de Posselt :**\nReprésentation graphique de tous les mouvements mandibulaires bordants (arabesque : RC, OIM, repos, propulsion max, latéralités)"}
  ,{id:"pd_f11",title:"Gestion du laboratoire de prothèse : qualité, finances et RH",bloc:"Bloc 3",tags:["ISO 13485","Bon de travail","Traçabilité","Coût de revient","Seuil de rentabilité","SIG","RSE","DUERP","Amortissement","Statuts juridiques"],duree:22,niveau:"Intermédiaire",qbank:"pd_gestion_lab",
    contenu:"**Réglementation et qualité :**\n• Bon de travail (BTL) : document médico-légal obligatoire (MDR 2017/745)\n• Prothèse = DM sur mesure classe IIa → traçabilité 10 ans (matériaux + lots + opérateurs)\n• ISO 13485 : SMQ pour fabricants DM → gestion risques (ISO 14971), validation procédés, NC\n\n**Gestion financière :**\n• Coût de revient = matières premières + MO directe + charges indirectes (amortissements, frais généraux)\n• Seuil de rentabilité (SR) = Charges fixes / TMCV (taux de marge sur coût variable)\n• SIG : VA = Marge brute − Consommations externes ; EBE = VA − Charges de personnel\n• Amortissement linéaire = coût HT / durée de vie (charge comptable ≠ sortie de trésorerie)\n\n**Statuts juridiques :**\n• SARL : gérant TNS (SSI, cotisations moindres), EURL = version unipersonnelle\n• SAS/SASU : président assimilé salarié (régime général, meilleure protection)\n\n**Ressources humaines :**\n• CCN prothésistes dentaires (IDCC 1996) : grille salariale, conditions de travail, CPF\n• DUERP : obligatoire dès 1 salarié, inventaire des risques, mis à jour annuellement\n\n**RSE :** 3 piliers : économique (rentabilité durable) + social (bien-être salariés) + environnemental (déchets, énergie)\n\n**Risques professionnels :**\n• Poussières : zircone, PMMA → FFP2/FFP3 + aspiration\n• Bruit : fraiseuses > 85 dB → protection auditive\n• Chimiques : MMA (allergisant) → gants nitrile, ventilation"}
  ,{id:"pd_f12",title:"CFAO avancée : empreintes numériques, CAD et contrôle qualité",bloc:"Bloc 3",tags:["Empreinte optique","STL","exocad","Fraisage MOCN","Zircone","Frittage","Impression 3D SLA","PEEK","SLM","Contrôle dimensional"],duree:22,niveau:"Avancé",qbank:"pd_cfao2",
    contenu:"**Acquisition numérique :**\n• Scanner intra-oral (CEREC Primescan, iTero, 3Shape TRIOS) → fichier STL en temps réel\n• Avantages : confort patient, pas de déformation, transmission instantanée\n• Scanner de bureau : scanne modèles plâtre, précision ≤ 10 µm, coût 3-10 k€\n\n**Conception CAD :**\n• exocad (Dentsply Sirona) : leader mondial, modules couronne/bridge/châssis/implant/ODF\n• 3Shape Dental System : concurrent principal\n• Bibliothèques de dents, d'implants, wax-up numérique (DDS)\n\n**Fraisage MOCN :**\n• 5 axes, broches 50 000-300 000 tr/min, précision ± 20-50 µm\n• Zircone préfrittée → frittage 1450-1550°C → retrait dimensionnel 20-25% (compensé en CAD)\n• 3Y-TZP (≈ 1200 MPa, opaque) ; 5Y-PSZ (translucide, ≈ 700-900 MPa)\n\n**Impression 3D :**\n• SLA (laser UV) / DLP (lumière projetée) → modèles, guides chirurgicaux, provisoires, plaques-bases\n• SLM/LPBF (fusion poudre métallique) : châssis Co-Cr ou Ti, géométries complexes\n• PEEK (PolyEtherEtherKetone) : châssis PAP, module proche de l'os, biocompatible\n\n**Contrôle qualité numérique :**\n• Scan pièce finie → superposition colorisée sur le fichier CAD d'origine → carte de déviation\n• Tolérance : 50-100 µm selon les zones\n• Portails numériques (3Shape Communicate, CEREC Connect) : transfert STL + photos + consignes"}
  ,{id:"pd_f6",title:"Parodontologie, réglementation MDR et hygiène",bloc:"Bloc 3",tags:["Parodontologie","MDR","DASRI","Traçabilité","Hygiène"],duree:18,niveau:"Intermédiaire",qbank:"pd_paro_hygiene",
    contenu:"**Parodonte :**\n• Gingivite : réversible (inflammation gencive sans perte d'attache)\n• Parodontite : perte d'attache irréversible (os alvéolaire, ligament, cément)\n• Sondage parodontal : 0-3 mm normal, > 4 mm = poche pathologique\n• Indice de plaque (Silness-Löe) : 0-3\n\n**Réglementation MDR 2017/745 :**\n• Prothèses dentaires sur mesure = DM classe IIa\n• Bon de travail (prescription) obligatoire\n• Traçabilité : matériaux, lots, opérateurs → conservation 10 ans\n• Déclaration de conformité CE\n\n**Hygiène au laboratoire :**\n• Empreintes et prothèses : désinfection dès réception (glutaraldéhyde, hypochlorite)\n• EPI : masque FFP2 (poussières zircone/PMMA), gants nitrile, lunettes\n• Autoclave : 121°C/15 min (instruments réutilisables)\n• DASRI : empreintes, gants, déchets potentiellement contaminés\n\n**Communication :**\n• Bon de travail : identification patient, prothèse, teinte, matériaux, date\n• Teinte : VITA 3D Master ou Classical + spectrophotomètre\n• Articulateur semi-adaptable : pente condylienne + angle de Bennett"}
];

